import Foundation
import CoreGraphics
import CaptureDeskCore

// ---------------------------------------------------------------------------
// MARK: - Canon EDSDK Driver
//
// HOW TO ACTIVATE WHEN YOUR SDK ARRIVES:
//
// 1. Create Sources/CaptureDeskTethering/EDSDK/ and drop the SDK headers into it:
//      EDSDK.h  EDSDKErrors.h  EDSDKTypes.h
//
// 2. Create Sources/CaptureDeskTethering/EDSDKBridge.h (umbrella) and
//    Sources/CaptureDeskTethering/EDSDKBridge.m (shim) — see template at end of file.
//
// 3. Place EDSDK.framework in the repo at Frameworks/EDSDK.framework
//    and add to Package.swift:
//      .target("CaptureDeskTethering", ...,
//          linkerSettings: [
//              .linkedFramework("ImageCaptureCore"),
//              .unsafeFlags(["-F", "Frameworks", "-framework", "EDSDK",
//                            "-Xlinker", "-rpath", "-Xlinker", "@executable_path/../Frameworks"])
//          ]
//      )
//
// 4. In AppState.swift change:
//      RecoveringCameraDriver(base: ICADriver())
//    to:
//      RecoveringCameraDriver(base: EDSDKDriver())
//
// 5. swift build — done.
//
// ---------------------------------------------------------------------------
//
// EDSDK API summary (Canon EOS Digital SDK):
//
//   EdsInitializeSDK()         — must be called once on main thread
//   EdsTerminateSDK()          — cleanup on exit
//   EdsGetCameraList()         — returns EdsBaseRef to camera list
//   EdsGetChildCount()         — number of cameras in list
//   EdsGetChildAtIndex()       — get EdsCameraRef at index
//   EdsGetDeviceInfo()         — model name, port, bodyID (serial)
//   EdsOpenSession(camera)     — open PTP session (blocks until ready)
//   EdsCloseSession(camera)    — close PTP session
//   EdsSendCommand(camera, kEdsCameraCommand_TakePicture, 0)  — trigger
//   EdsSetObjectEventHandler() — callback for object-added events
//   EdsDownloadFile()          — transfer file from camera
//   EdsRelease()               — release any EdsBaseRef
//
// ---------------------------------------------------------------------------

/// Canon EDSDK driver — full implementation pending SDK delivery.
///
/// While the SDK is in transit this type compiles and satisfies the `CameraDriver`
/// protocol so the rest of the codebase can be built and tested. All operations
/// return meaningful errors explaining the SDK is not yet linked.
public actor EDSDKDriver: CameraDriver {

    public private(set) var connectionState: CameraConnectionState = .disconnected
    public private(set) var connectedDevice: CameraDevice? = nil
    public private(set) var exposureState: CameraExposureState = .init()
    public private(set) var driverNotes: String = "Canon EDSDK driver — SDK not yet linked. Awaiting framework delivery."
    public private(set) var healthSnapshot: TetherHealthSnapshot = .init(
        state: .disconnected,
        level: .nominal,
        diagnosticsSummary: "EDSDK driver loaded — link EDSDK.framework to activate"
    )

    private var activeSession: CaptureSession?

    public init() {}

    public func prepareSession(_ session: CaptureSession?) async {
        activeSession = session
    }

    // MARK: - Discovery

    public func discoverDevices() async throws -> [CameraDevice] {
        // ----- EDSDK implementation stub -----
        // When SDK is linked, replace this body with:
        //
        //   guard EdsInitializeSDK() == EDS_ERR_OK else { throw EDSDKError.initFailed }
        //   defer { EdsTerminateSDK() }
        //   var listRef: EdsBaseRef?
        //   EdsGetCameraList(&listRef)
        //   defer { if let r = listRef { EdsRelease(r) } }
        //   var count: EdsUInt32 = 0
        //   EdsGetChildCount(listRef, &count)
        //   var cameras: [CameraDevice] = []
        //   for i in 0..<Int(count) {
        //       var camRef: EdsBaseRef?
        //       EdsGetChildAtIndex(listRef, EdsInt32(i), &camRef)
        //       defer { if let r = camRef { EdsRelease(r) } }
        //       var info = EdsDeviceInfo()
        //       EdsGetDeviceInfo(camRef, &info)
        //       let name = String(cString: &info.szDeviceDescription.0)
        //       let serial = String(cString: &info.szPortName.0)  // use bodyID for serial
        //       cameras.append(CameraDevice(modelName: name, manufacturer: "Canon",
        //           serialNumber: serial, batteryLevel: 0, vendor: .canon,
        //           capabilities: .init(supportsRemoteCapture: true, supportsLiveView: true,
        //               supportsExposureControl: true, supportsFileEvents: true,
        //               notes: "Canon EDSDK")))
        //   }
        //   return cameras
        // ----- end stub -----

        connectionState = .ready
        healthSnapshot = TetherHealthSnapshot(
            state: .ready,
            level: .degraded,
            diagnosticsSummary: "EDSDK.framework not yet linked — awaiting SDK delivery from Canon"
        )
        driverNotes = "EDSDK driver stub active. Link EDSDK.framework and implement the EdsGetCameraList path above."
        return []
    }

    // MARK: - Connection

    public func connect(to device: CameraDevice) async throws {
        // When SDK linked:
        //   EdsOpenSession(cameraRef)
        //   connectionState = .ready
        throw NSError(
            domain: "CaptureDesk.EDSDKDriver",
            code: 503,
            userInfo: [NSLocalizedDescriptionKey: "EDSDK.framework not linked yet — awaiting SDK delivery."]
        )
    }

    public func disconnect() async {
        // When SDK linked: EdsCloseSession(cameraRef); EdsTerminateSDK()
        connectedDevice = nil
        connectionState = .disconnected
    }

    // MARK: - Capture

    public func capture(into session: CaptureSession) async throws -> CaptureResult {
        // When SDK linked:
        //   EdsSendCommand(cameraRef, kEdsCameraCommand_TakePicture, 0)
        //   wait for EDS_ObjectEvent_DirItemCreated callback
        //   EdsDownloadFile(item, downloadDir, &fileRef)
        //   return CaptureResult(asset: ...)
        throw NSError(
            domain: "CaptureDesk.EDSDKDriver",
            code: 503,
            userInfo: [NSLocalizedDescriptionKey: "EDSDK.framework not linked yet — awaiting SDK delivery."]
        )
    }

    // MARK: - Live View

    public func startLiveView(frameHandler: @escaping @Sendable (CGImage) -> Void) async throws {
        // When SDK linked:
        //   EdsSendCommand(cameraRef, kEdsCameraCommand_DoEvfAf, kEdsEvfAf_ON)
        //   EdsCreateEvfImageRef / EdsDownloadEvfImage in a poll loop
        throw NSError(
            domain: "CaptureDesk.EDSDKDriver",
            code: 503,
            userInfo: [NSLocalizedDescriptionKey: "Live view requires EDSDK.framework — awaiting SDK delivery."]
        )
    }

    public func stopLiveView() async {
        // When SDK linked: EdsSendCommand(cameraRef, kEdsCameraCommand_DoEvfAf, kEdsEvfAf_OFF)
    }
}

// ---------------------------------------------------------------------------
// MARK: - EDSDKBridge shim template (copy to EDSDKBridge.m when SDK arrives)
//
// This shim wraps EDSDK's C API in a form Swift can call via the bridging header.
//
// EDSDKBridge.h:
// ---------------------------------------------------------------------------
// #pragma once
// #import <Foundation/Foundation.h>
// #import "EDSDK/EDSDK.h"
//
// NS_ASSUME_NONNULL_BEGIN
//
// typedef void (^EDSObjectEventBlock)(EdsUInt32 event, EdsBaseRef object, EdsVoid* context);
//
// EdsError eds_initialize(void);
// EdsError eds_terminate(void);
// EdsError eds_get_camera_list(EdsBaseRef _Nullable * _Nonnull outList);
// EdsError eds_get_child_count(EdsBaseRef list, EdsUInt32 *outCount);
// EdsError eds_get_child_at_index(EdsBaseRef list, EdsInt32 index, EdsBaseRef _Nullable * _Nonnull outChild);
// EdsError eds_get_device_info(EdsBaseRef camera, EdsDeviceInfo *outInfo);
// EdsError eds_open_session(EdsBaseRef camera);
// EdsError eds_close_session(EdsBaseRef camera);
// EdsError eds_take_picture(EdsBaseRef camera);
// EdsError eds_download_file(EdsBaseRef dirItem, const char *destPath);
// EdsError eds_release(EdsBaseRef ref);
// EdsError eds_set_object_event_handler(EdsBaseRef camera, EdsUInt32 event,
//                                        EDSObjectEventBlock handler);
//
// NS_ASSUME_NONNULL_END
// ---------------------------------------------------------------------------
//
// EDSDKBridge.m:
// ---------------------------------------------------------------------------
// #import "EDSDKBridge.h"
//
// EdsError eds_initialize(void) { return EdsInitializeSDK(); }
// EdsError eds_terminate(void)  { return EdsTerminateSDK();  }
//
// EdsError eds_get_camera_list(EdsBaseRef *outList) {
//     return EdsGetCameraList(outList);
// }
// EdsError eds_get_child_count(EdsBaseRef list, EdsUInt32 *outCount) {
//     return EdsGetChildCount(list, outCount);
// }
// EdsError eds_get_child_at_index(EdsBaseRef list, EdsInt32 index, EdsBaseRef *outChild) {
//     return EdsGetChildAtIndex(list, index, outChild);
// }
// EdsError eds_get_device_info(EdsBaseRef camera, EdsDeviceInfo *outInfo) {
//     return EdsGetDeviceInfo(camera, outInfo);
// }
// EdsError eds_open_session(EdsBaseRef camera)  { return EdsOpenSession(camera);  }
// EdsError eds_close_session(EdsBaseRef camera) { return EdsCloseSession(camera); }
//
// EdsError eds_take_picture(EdsBaseRef camera) {
//     return EdsSendCommand(camera, kEdsCameraCommand_TakePicture, 0);
// }
//
// EdsError eds_download_file(EdsBaseRef dirItem, const char *destPath) {
//     EdsDirectoryItemInfo info;
//     EdsGetDirectoryItemInfo(dirItem, &info);
//     EdsStreamRef stream = NULL;
//     EdsCreateFileStream(destPath, kEdsFileCreateDisposition_CreateAlways,
//                         kEdsAccess_ReadWrite, &stream);
//     EdsError err = EdsDownload(dirItem, info.size, stream);
//     EdsDownloadComplete(dirItem);
//     EdsRelease(stream);
//     return err;
// }
//
// EdsError eds_release(EdsBaseRef ref) { return EdsRelease(ref); }
//
// static EdsUInt32 EDSCALLBACK _objectEventCB(EdsUInt32 event, EdsBaseRef object, EdsVoid* ctx) {
//     EDSObjectEventBlock block = (__bridge EDSObjectEventBlock)ctx;
//     if (block) block(event, object, ctx);
//     return EDS_ERR_OK;
// }
//
// EdsError eds_set_object_event_handler(EdsBaseRef camera, EdsUInt32 event,
//                                        EDSObjectEventBlock handler) {
