182	public struct CanonEDSDKBackend: VendorCameraBackend {
183	    public let vendor: CameraVendor = .canon
184	    public let integrationStatus = "Canon bridge seam is compile-real but SDK-free in-source. The runtime can use a private CLI bridge or wrapper target for EDSDK/PTP event routing, connection ownership, capture completion, and watchdog-style recovery without shipping Canon binaries here."
185	
186	    public init() {}
187	
188	    public func discoverMockDevices() async -> [CameraDevice] {
189	        guard let bridge = VendorBridgeRegistry.bridge(for: .canon),
190	              let devices = try? await bridge.discoverDevices(),
191	              devices.isEmpty == false else { return [] }
192	        let profile = await bridge.profile()
193	        return devices.map {
194	            CameraDevice(
195	                modelName: $0.modelName,
196	                manufacturer: $0.manufacturer,
197	                serialNumber: $0.serialNumber,
198	                batteryLevel: $0.batteryLevel,
199	                vendor: .canon,
200	                capabilities: .init(
201	                    supportsRemoteCapture: profile.supportsRemoteCapture,
202	                    supportsLiveView: profile.supportsLiveView,
203	                    supportsExposureControl: profile.supportsExposureControl,
204	                    supportsFileEvents: profile.supportsFileEvents,
205	                    notes: integrationStatus + " " + profile.operationalNotes
206	                )
207	            )
208	        }
209	    }
210	
211	    public func connect(to device: CameraDevice) async throws -> CameraDevice {
212	        if let bridge = VendorBridgeRegistry.bridge(for: .canon) {
213	            try await bridge.connect(serialNumber: device.serialNumber)
214	        }
215	        try await Task.sleep(for: .milliseconds(140))
216	        var connected = device
217	        connected.isConnected = true
218	        return connected
219	    }
220	
221	    public func disconnect(from device: CameraDevice) async {
222	        if let bridge = VendorBridgeRegistry.bridge(for: .canon) {
223	            try? await bridge.disconnect(serialNumber: device.serialNumber)
224	        }
225	    }
226	
227	    public func capture(into session: CaptureSession, device: CameraDevice, exposure: CameraExposureState) async throws -> CaptureResult {
228	        if let bridge = VendorBridgeRegistry.bridge(for: .canon), let captureURL = session.folderURL(for: .capture) {
229	            let payload = try await bridge.triggerCapture(into: captureURL)
230	            return CaptureResult(asset: CaptureAsset(sessionID: session.id, fileURL: payload.fileURL, capturedAt: .now, cameraName: payload.cameraName, lensName: payload.lensName, iso: payload.iso, shutterSpeed: payload.shutterSpeed, aperture: payload.aperture), exposure: exposure)
231	        }
232	        return try await GeneratedCaptureWriter.writeJPEG(into: session, device: device, exposure: exposure, accent: (0.76, 0.18, 0.19))
233	    }
234	}
