312	public actor CompositeCameraDriver: CameraDriver {
313	    public private(set) var connectionState: CameraConnectionState = .disconnected
314	    public private(set) var connectedDevice: CameraDevice?
315	    public private(set) var exposureState: CameraExposureState = .init()
316	    public private(set) var driverNotes: String = "Mock/PTP scaffold active"
317	    public private(set) var healthSnapshot: TetherHealthSnapshot = .init()
318	
319	    private let backends: [CameraVendor: VendorCameraBackend]
320	    private var lastDiscovery: [CameraDevice] = []
321	    private var liveViewTask: Task<Void, Never>?
322	
323	    public init(
324	        canon: VendorCameraBackend = CanonEDSDKBackend(),
325	        nikon: VendorCameraBackend = NikonSDKBackend(),
326	        generic: VendorCameraBackend = MockPTPBackend()
327	    ) {
328	        self.backends = [
329	            .canon: canon,
330	            .nikon: nikon,
331	            .genericPTP: generic,
332	            .mock: generic
333	        ]
334	    }
335	
336	    public func discoverDevices() async throws -> [CameraDevice] {
337	        transition(to: .discovering, level: .nominal, summary: "Scanning for tether-capable cameras")
338	        do {
339	            try await Task.sleep(for: .milliseconds(220))
340	            var discovered: [CameraDevice] = []
341	            for backend in uniqueBackends() {
342	                let devices = await backend.discoverMockDevices()
343	                discovered.append(contentsOf: devices)
344	            }
345	            let devices = Array(Dictionary(grouping: discovered, by: { "\($0.vendor.rawValue)|\($0.serialNumber)" }).values.compactMap(\.first))
346	                .sorted { lhs, rhs in
347	                    (lhs.manufacturer, lhs.modelName, lhs.serialNumber) < (rhs.manufacturer, rhs.modelName, rhs.serialNumber)
348	                }
349	            lastDiscovery = devices
350	            transition(to: .ready, level: devices.isEmpty ? .degraded : .nominal, summary: devices.isEmpty ? "No cameras discovered" : "Discovered \(devices.count) camera(s)")
351	            return devices
352	        } catch {
353	            record(error: error, state: .error, summary: "Camera discovery failed")
354	            throw error
355	        }
356	    }
357	
358	    public func connect(to device: CameraDevice) async throws {
359	        guard let backend = backends[device.vendor] else {
360	            throw NSError(domain: "CaptureDesk.CompositeCameraDriver", code: 404, userInfo: [NSLocalizedDescriptionKey: "No backend registered for \(device.vendor.rawValue)"])
361	        }
362	
363	        if let existing = connectedDevice, existing.serialNumber != device.serialNumber {
364	            await disconnectCurrentDevice(reason: "Switching to \(device.modelName)")
365	        }
366	
367	        transition(to: .connecting, level: .nominal, device: device, summary: "Connecting to \(device.modelName)")
368	        do {
369	            let connected = try await backend.connect(to: device)
370	            connectedDevice = connected
371	            driverNotes = backend.integrationStatus + "\nCapabilities: \(capabilitySummary(for: connected.capabilities))"
372	            transition(to: .connected, level: .nominal, device: connected, summary: "Transport connected to \(connected.modelName)")
373	            transition(to: .ready, level: .nominal, device: connected, summary: "Ready for capture")
374	        } catch {
375	            record(error: error, state: .error, device: device, summary: "Camera connect failed")
376	            throw error
377	        }
378	    }
379	
380	    public func disconnect() async {
381	        await disconnectCurrentDevice(reason: "Disconnected camera session")
382	    }
383	
384	    public func capture(into session: CaptureSession) async throws -> CaptureResult {
385	        guard let connectedDevice else {
386	            let error = NSError(domain: "CaptureDesk.CompositeCameraDriver", code: 400, userInfo: [NSLocalizedDescriptionKey: "No active camera connection."])
387	            record(error: error, state: .error, summary: "Capture requested without an active device")
388	            throw error
389	        }
390	        guard let backend = backends[connectedDevice.vendor] else {
391	            let error = NSError(domain: "CaptureDesk.CompositeCameraDriver", code: 404, userInfo: [NSLocalizedDescriptionKey: "No backend registered for \(connectedDevice.vendor.rawValue)"])
392	            record(error: error, state: .error, device: connectedDevice, summary: "Capture backend missing")
393	            throw error
394	        }
395	        transition(to: .capturing, level: .nominal, device: connectedDevice, summary: "Triggering capture")
396	        do {
397	            let result = try await backend.capture(into: session, device: connectedDevice, exposure: exposureState)
398	            healthSnapshot.lastCaptureAt = .now
399	            transition(to: .ready, level: .nominal, device: connectedDevice, summary: "Capture completed: \(result.asset.fileURL.lastPathComponent)")
400	            return result
401	        } catch {
402	            record(error: error, state: .error, device: connectedDevice, summary: "Capture failed")
403	            throw error
404	        }
405	    }
406	
407	    // MARK: - Live View
408	
409	    public func startLiveView(frameHandler: @escaping @Sendable (CGImage) -> Void) async throws {
410	        guard let connectedDevice, connectedDevice.capabilities.supportsLiveView else {
411	            // Run mock live view for demo / devices that don't support it yet
412	            liveViewTask = Task {
413	                var frame = 0
414	                while !Task.isCancelled {
415	                    if let image = MockLiveViewGenerator.makeFrame(frame: frame) {
416	                        frameHandler(image)
417	                    }
418	                    frame += 1
419	                    try? await Task.sleep(for: .milliseconds(67))  // ~15 fps
420	                }
421	            }
422	            return
423	        }
424	        // Real vendor live view would call the vendor SDK here;
425	        // for now fall through to mock even for supported devices
426	        liveViewTask = Task {
427	            var frame = 0
428	            while !Task.isCancelled {
429	                if let image = MockLiveViewGenerator.makeFrame(frame: frame, label: connectedDevice.modelName) {
430	                    frameHandler(image)
431	                }
432	                frame += 1
433	                try? await Task.sleep(for: .milliseconds(67))
434	            }
435	        }
436	    }
437	
438	    public func stopLiveView() async {
439	        liveViewTask?.cancel()
440	        liveViewTask = nil
441	    }
442	
443	    private func uniqueBackends() -> [VendorCameraBackend] {
444	        var seen: Set<CameraVendor> = []
445	        return backends.values.filter { backend in
446	            guard seen.contains(backend.vendor) == false else { return false }
447	            seen.insert(backend.vendor)
448	            return true
449	        }
450	    }
451	
452	    private func disconnectCurrentDevice(reason: String) async {
453	        if let device = connectedDevice, let backend = backends[device.vendor] {
454	            await backend.disconnect(from: device)
455	        }
456	        connectedDevice = nil
457	        transition(to: .disconnected, level: .nominal, device: nil, summary: reason)
458	    }
459	
460	    private func transition(to state: CameraConnectionState, level: TetherHealthLevel, device: CameraDevice? = nil, summary: String) {
461	        connectionState = state
462	        if let device {
463	            healthSnapshot.activeVendor = device.vendor
464	            healthSnapshot.activeCameraName = device.modelName
465	        } else if state == .disconnected {
466	            healthSnapshot.activeVendor = nil
467	            healthSnapshot.activeCameraName = nil
468	        }
469	        healthSnapshot.state = state
470	        healthSnapshot.level = level
471	        healthSnapshot.lastStateChangeAt = .now
472	        healthSnapshot.diagnosticsSummary = summary
473	        if level != .faulted {
474	            healthSnapshot.lastError = nil
475	        }
476	    }
477	
478	    private func record(error: Error, state: CameraConnectionState, device: CameraDevice? = nil, summary: String) {
479	        transition(to: state, level: .faulted, device: device, summary: summary)
480	        healthSnapshot.lastError = error.localizedDescription
481	        driverNotes = [driverNotes, "Last error: \(error.localizedDescription)"].filter { $0.isEmpty == false }.joined(separator: "\n")
482	    }
483	
484	    private func capabilitySummary(for capabilities: CameraCapabilitySet) -> String {
485	        let items = [
486	            capabilities.supportsRemoteCapture ? "remote capture" : nil,
487	            capabilities.supportsLiveView ? "live view" : nil,
488	            capabilities.supportsExposureControl ? "exposure control" : nil,
489	            capabilities.supportsFileEvents ? "file events" : nil
490	        ].compactMap { $0 }
491	        return items.isEmpty ? "none" : items.joined(separator: ", ")
492	    }
493	}
