496	
497	enum MockLiveViewGenerator {
498	    static func makeFrame(frame: Int, label: String = "Live View") -> CGImage? {
499	        let width = 1920, height = 1280
500	        let colorSpace = CGColorSpace(name: CGColorSpace.sRGB)!
501	        guard let ctx = CGContext(data: nil, width: width, height: height,
502	                                   bitsPerComponent: 8, bytesPerRow: width * 4,
503	                                   space: colorSpace,
504	                                   bitmapInfo: CGImageAlphaInfo.premultipliedLast.rawValue) else { return nil }
505	
506	        // Animated background — slow pan & brightness pulse
507	        let t = Double(frame) / 30.0
508	        let brightness = CGFloat(0.08 + sin(t * 0.7) * 0.02)
509	        ctx.setFillColor(CGColor(red: brightness * 0.6, green: brightness * 0.7, blue: brightness, alpha: 1))
510	        ctx.fill(CGRect(x: 0, y: 0, width: width, height: height))
511	
512	        // Studio grid lines
513	        ctx.setStrokeColor(CGColor(gray: 1, alpha: 0.06))
514	        ctx.setLineWidth(1)
515	        for x in stride(from: 0, through: width, by: width / 3) {
516	            ctx.move(to: CGPoint(x: x, y: 0)); ctx.addLine(to: CGPoint(x: x, y: height))
517	        }
518	        for y in stride(from: 0, through: height, by: height / 3) {
519	            ctx.move(to: CGPoint(x: 0, y: y)); ctx.addLine(to: CGPoint(x: width, y: y))
520	        }
521	        ctx.strokePath()
522	
523	        // Focus peaking strip (simulated)
524	        let stripY = Int(CGFloat(height) * 0.45 + sin(t * 1.2) * CGFloat(height) * 0.04)
525	        ctx.setStrokeColor(CGColor(red: 1, green: 0.2, blue: 0.2, alpha: 0.55))
526	        ctx.setLineWidth(2)
527	        ctx.move(to: CGPoint(x: 0, y: stripY)); ctx.addLine(to: CGPoint(x: width, y: stripY))
528	        ctx.strokePath()
529	
530	        // Center subject placeholder (circle + cross)
531	        let cx = CGFloat(width) / 2, cy = CGFloat(height) / 2
532	        let r: CGFloat = 180
533	        ctx.setStrokeColor(CGColor(gray: 1, alpha: 0.25))
534	        ctx.setLineWidth(1)
535	        ctx.strokeEllipse(in: CGRect(x: cx - r, y: cy - r, width: r * 2, height: r * 2))
536	        ctx.move(to: CGPoint(x: cx - r * 0.3, y: cy)); ctx.addLine(to: CGPoint(x: cx + r * 0.3, y: cy))
537	        ctx.move(to: CGPoint(x: cx, y: cy - r * 0.3)); ctx.addLine(to: CGPoint(x: cx, y: cy + r * 0.3))
538	        ctx.strokePath()
539	
540	        // HUD overlay — bottom strip
541	        ctx.setFillColor(CGColor(gray: 0, alpha: 0.60))
542	        ctx.fill(CGRect(x: 0, y: 0, width: width, height: 52))
543	
544	        // Framing: label text via bitmap encoding
545	        let hudText = "\(label)  |  1/125  f/2.8  ISO 400  |  LIVE"
546	        let textData = Data(hudText.utf8)
547	        for (i, byte) in textData.prefix(120).enumerated() {
548	            let v = CGFloat(byte) / 255.0
549	            ctx.setFillColor(CGColor(red: 0.2, green: 0.9, blue: 0.5, alpha: 0.8))
550	            ctx.fill(CGRect(x: 20 + i * 13, y: 14, width: 6, height: Int(v * 24) + 6))
551	        }
552	
553	        return ctx.makeImage()
554	    }
555	}
556	
557	enum GeneratedCaptureWriter {
558	    static func writeJPEG(into session: CaptureSession, device: CameraDevice, exposure: CameraExposureState, accent: (CGFloat, CGFloat, CGFloat)) async throws -> CaptureResult {
559	        guard let captureURL = session.folderURL(for: .capture) else {
560	            throw NSError(domain: "CaptureDesk.GeneratedCaptureWriter", code: 404, userInfo: [NSLocalizedDescriptionKey: "Capture folder missing from session."])
561	        }
562	
563	        try FileManager.default.createDirectory(at: captureURL, withIntermediateDirectories: true)
564	        try await Task.sleep(for: .milliseconds(180))
565	
566	        let timestamp = ISO8601DateFormatter().string(from: .now).replacingOccurrences(of: ":", with: "-")
567	        let filename = "CAP_\(device.vendor.rawValue.uppercased())_\(timestamp).jpg"
568	        let fileURL = uniqueFileURL(in: captureURL, preferredName: filename)
569	        try makeJPEG(at: fileURL, title: device.modelName, accent: accent, exposure: exposure)
570	
571	        let asset = CaptureAsset(
572	            sessionID: session.id,
573	            fileURL: fileURL,
574	            capturedAt: .now,
575	            cameraName: device.modelName,
576	            lensName: device.vendor == .canon ? "RF 24-70mm f/2.8L" : (device.vendor == .nikon ? "NIKKOR Z 24-70mm f/2.8 S" : "Studio Prime 80mm"),
577	            iso: exposure.iso,
578	            shutterSpeed: exposure.shutterSpeed,
579	            aperture: Double(exposure.aperture.replacingOccurrences(of: "f/", with: "")) ?? 2.8
580	        )
581	
582	        return CaptureResult(asset: asset, exposure: exposure)
583	    }
584	
585	    private static func uniqueFileURL(in directory: URL, preferredName: String) -> URL {
586	        let candidate = directory.appendingPathComponent(preferredName)
587	        guard FileManager.default.fileExists(atPath: candidate.path) else { return candidate }
588	
589	        let base = candidate.deletingPathExtension().lastPathComponent
590	        let ext = candidate.pathExtension
591	        for index in 1...999 {
592	            let next = directory.appendingPathComponent("\(base)-\(index)").appendingPathExtension(ext)
593	            if FileManager.default.fileExists(atPath: next.path) == false {
594	                return next
595	            }
596	        }
597	        return directory.appendingPathComponent(UUID().uuidString).appendingPathExtension(ext)
598	    }
599	
600	    private static func makeJPEG(at url: URL, title: String, accent: (CGFloat, CGFloat, CGFloat), exposure: CameraExposureState) throws {
601	        let width = 2400
602	        let height = 1600
603	        let colorSpace = CGColorSpace(name: CGColorSpace.sRGB)!
604	        guard let context = CGContext(data: nil, width: width, height: height, bitsPerComponent: 8, bytesPerRow: width * 4, space: colorSpace, bitmapInfo: CGImageAlphaInfo.premultipliedLast.rawValue) else {
605	            throw NSError(domain: "CaptureDesk.GeneratedCaptureWriter", code: 500, userInfo: [NSLocalizedDescriptionKey: "Failed to create bitmap context"])
606	        }
607	
608	        let base = CGColor(red: accent.0, green: accent.1, blue: accent.2, alpha: 1)
609	        let dark = CGColor(red: accent.0 * 0.2, green: accent.1 * 0.2, blue: accent.2 * 0.25, alpha: 1)
610	        context.setFillColor(dark)
611	        context.fill(CGRect(x: 0, y: 0, width: width, height: height))
612	
613	        for index in 0..<12 {
614	            let alpha = CGFloat(index + 1) / 14.0
615	            context.setFillColor(base.copy(alpha: alpha * 0.12) ?? base)
616	            context.fillEllipse(in: CGRect(x: 120 + index * 120, y: 220 + index * 40, width: 900, height: 900))
617	        }
618	
619	        context.setStrokeColor(CGColor(gray: 1, alpha: 0.22))
620	        context.setLineWidth(6)
621	        context.stroke(CGRect(x: 60, y: 60, width: width - 120, height: height - 120))
622	
623	        let bandHeight = 180
624	        context.setFillColor(CGColor(gray: 0.06, alpha: 0.86))
625	        context.fill(CGRect(x: 0, y: 0, width: width, height: bandHeight))
626	
627	        let metadata = "\(title)  •  ISO \(exposure.iso)  •  \(exposure.shutterSpeed)  •  \(exposure.aperture)"
628	        let data = Data(metadata.utf8)
629	        for (offset, byte) in data.prefix(800).enumerated() {
630	            let value = CGFloat(byte) / 255.0
631	            context.setFillColor(CGColor(red: value, green: 1 - value, blue: 0.72, alpha: 0.85))
632	            context.fill(CGRect(x: 80 + (offset * 8), y: 72, width: 5, height: 44 + Int(value * 44)))
633	        }
634	
635	        guard let image = context.makeImage() else {
636	            throw NSError(domain: "CaptureDesk.GeneratedCaptureWriter", code: 501, userInfo: [NSLocalizedDescriptionKey: "Failed to create CGImage"])
637	        }
638	        guard let destination = CGImageDestinationCreateWithURL(url as CFURL, UTType.jpeg.identifier as CFString, 1, nil) else {
639	            throw NSError(domain: "CaptureDesk.GeneratedCaptureWriter", code: 502, userInfo: [NSLocalizedDescriptionKey: "Failed to create image destination"])
640	        }
641	        CGImageDestinationAddImage(destination, image, [kCGImageDestinationLossyCompressionQuality: 0.92] as CFDictionary)
642	        guard CGImageDestinationFinalize(destination) else {
643	            throw NSError(domain: "CaptureDesk.GeneratedCaptureWriter", code: 503, userInfo: [NSLocalizedDescriptionKey: "Failed to finalize image destination"])
644	        }
645	    }
646	}
