import Foundation
import CoreGraphics
import ImageIO
import UniformTypeIdentifiers
import CaptureDeskCore
import CaptureDeskVendorSupport

public enum CameraConnectionState: String, Codable, Sendable {
    case disconnected
    case discovering
    case connecting
    case connected
    case ready
    case capturing
    case reconnecting
    case error
}

public enum TetherHealthLevel: String, Codable, Sendable {
    case nominal
    case degraded
    case recovering
    case faulted
}

public struct TetherHealthSnapshot: Hashable, Codable, Sendable {
    public var state: CameraConnectionState
    public var level: TetherHealthLevel
    public var activeVendor: CameraVendor?
    public var activeCameraName: String?
    public var lastError: String?
    public var lastStateChangeAt: Date
    public var lastCaptureAt: Date?
    public var reconnectAttempts: Int
    public var totalRecoveryCount: Int
    public var sessionEventLogPath: URL?
    public var diagnosticsSummary: String

    public init(
        state: CameraConnectionState = .disconnected,
        level: TetherHealthLevel = .nominal,
        activeVendor: CameraVendor? = nil,
        activeCameraName: String? = nil,
        lastError: String? = nil,
        lastStateChangeAt: Date = .now,
        lastCaptureAt: Date? = nil,
        reconnectAttempts: Int = 0,
        totalRecoveryCount: Int = 0,
        sessionEventLogPath: URL? = nil,
        diagnosticsSummary: String = "Idle"
    ) {
        self.state = state
        self.level = level
        self.activeVendor = activeVendor
        self.activeCameraName = activeCameraName
        self.lastError = lastError
        self.lastStateChangeAt = lastStateChangeAt
        self.lastCaptureAt = lastCaptureAt
        self.reconnectAttempts = reconnectAttempts
        self.totalRecoveryCount = totalRecoveryCount
        self.sessionEventLogPath = sessionEventLogPath
        self.diagnosticsSummary = diagnosticsSummary
    }
}

public struct CameraCapabilitySet: Hashable, Codable, Sendable {
    public var supportsRemoteCapture: Bool
    public var supportsLiveView: Bool
    public var supportsExposureControl: Bool
    public var supportsFileEvents: Bool
    public var notes: String

    public init(
        supportsRemoteCapture: Bool = true,
        supportsLiveView: Bool = false,
        supportsExposureControl: Bool = true,
        supportsFileEvents: Bool = false,
        notes: String = ""
    ) {
        self.supportsRemoteCapture = supportsRemoteCapture
        self.supportsLiveView = supportsLiveView
        self.supportsExposureControl = supportsExposureControl
        self.supportsFileEvents = supportsFileEvents
        self.notes = notes
    }
}

public struct CameraDevice: Identifiable, Hashable, Codable, Sendable {
    public let id: UUID
    public var modelName: String
    public var manufacturer: String
    public var serialNumber: String
    public var batteryLevel: Int
    public var isConnected: Bool
    public var vendor: CameraVendor
    public var capabilities: CameraCapabilitySet

    public init(
        id: UUID = UUID(),
        modelName: String,
        manufacturer: String,
        serialNumber: String,
        batteryLevel: Int,
        isConnected: Bool = false,
        vendor: CameraVendor,
        capabilities: CameraCapabilitySet = .init()
    ) {
        self.id = id
        self.modelName = modelName
        self.manufacturer = manufacturer
        self.serialNumber = serialNumber
        self.batteryLevel = batteryLevel
        self.isConnected = isConnected
        self.vendor = vendor
        self.capabilities = capabilities
    }
}

public struct CameraExposureState: Hashable, Codable, Sendable {
    public var aperture: String
    public var shutterSpeed: String
    public var iso: Int
    public var whiteBalance: String

    public init(aperture: String = "f/2.8", shutterSpeed: String = "1/125", iso: Int = 100, whiteBalance: String = "5600K") {
        self.aperture = aperture
        self.shutterSpeed = shutterSpeed
        self.iso = iso
        self.whiteBalance = whiteBalance
    }
}

public struct CaptureResult: Hashable, Codable, Sendable {
    public var asset: CaptureAsset
    public var exposure: CameraExposureState

    public init(asset: CaptureAsset, exposure: CameraExposureState) {
        self.asset = asset
        self.exposure = exposure
    }
}

public protocol CameraDriver: Actor, Sendable {
    var connectionState: CameraConnectionState { get async }
    var connectedDevice: CameraDevice? { get async }
    var exposureState: CameraExposureState { get async }
    var driverNotes: String { get async }
    var healthSnapshot: TetherHealthSnapshot { get async }

    /// Called whenever the active session changes so the driver can route
    /// tethered file events to the correct folder. Default impl is a no-op.
    func prepareSession(_ session: CaptureSession?) async

    func discoverDevices() async throws -> [CameraDevice]
    func connect(to device: CameraDevice) async throws
    func disconnect() async
    func capture(into session: CaptureSession) async throws -> CaptureResult

    /// Start streaming live view frames. Calls `frameHandler` on each new frame.
    /// Implementations that do not support live view should throw or no-op.
    func startLiveView(frameHandler: @escaping @Sendable (CGImage) -> Void) async throws
    func stopLiveView() async
}

public extension CameraDriver {
    func prepareSession(_ session: CaptureSession?) async {}
    /// Attempt to revive underlying system daemons (ICA-specific). No-op for other drivers.
    func kickDaemons() async {}
    /// Instant check of currently-registered cameras without waiting. No-op for other drivers.
    func peekDiscoveredDevices() async -> [CameraDevice] { [] }
}

public protocol VendorCameraBackend: Sendable {
    var vendor: CameraVendor { get }
    var integrationStatus: String { get }
    func discoverMockDevices() async -> [CameraDevice]
    func connect(to device: CameraDevice) async throws -> CameraDevice
    func disconnect(from device: CameraDevice) async
    func capture(into session: CaptureSession, device: CameraDevice, exposure: CameraExposureState) async throws -> CaptureResult
}

public struct CanonEDSDKBackend: VendorCameraBackend {
    public let vendor: CameraVendor = .canon
    public let integrationStatus = "Canon bridge seam is compile-real but SDK-free in-source. The runtime can use a private CLI bridge or wrapper target for EDSDK/PTP event routing, connection ownership, capture completion, and watchdog-style recovery without shipping Canon binaries here."

    public init() {}

    public func discoverMockDevices() async -> [CameraDevice] {
        guard let bridge = VendorBridgeRegistry.bridge(for: .canon),
              let devices = try? await bridge.discoverDevices(),
              devices.isEmpty == false else { return [] }
        let profile = await bridge.profile()
        return devices.map {
            CameraDevice(
                modelName: $0.modelName,
                manufacturer: $0.manufacturer,
                serialNumber: $0.serialNumber,
                batteryLevel: $0.batteryLevel,
                vendor: .canon,
                capabilities: .init(
                    supportsRemoteCapture: profile.supportsRemoteCapture,
                    supportsLiveView: profile.supportsLiveView,
                    supportsExposureControl: profile.supportsExposureControl,
                    supportsFileEvents: profile.supportsFileEvents,
                    notes: integrationStatus + " " + profile.operationalNotes
                )
            )
        }
    }

    public func connect(to device: CameraDevice) async throws -> CameraDevice {
        if let bridge = VendorBridgeRegistry.bridge(for: .canon) {
            try await bridge.connect(serialNumber: device.serialNumber)
        }
        try await Task.sleep(for: .milliseconds(140))
        var connected = device
        connected.isConnected = true
        return connected
    }

    public func disconnect(from device: CameraDevice) async {
        if let bridge = VendorBridgeRegistry.bridge(for: .canon) {
            try? await bridge.disconnect(serialNumber: device.serialNumber)
        }
    }

    public func capture(into session: CaptureSession, device: CameraDevice, exposure: CameraExposureState) async throws -> CaptureResult {
        if let bridge = VendorBridgeRegistry.bridge(for: .canon), let captureURL = session.folderURL(for: .capture) {
            let payload = try await bridge.triggerCapture(into: captureURL)
            return CaptureResult(asset: CaptureAsset(sessionID: session.id, fileURL: payload.fileURL, capturedAt: .now, cameraName: payload.cameraName, lensName: payload.lensName, iso: payload.iso, shutterSpeed: payload.shutterSpeed, aperture: payload.aperture), exposure: exposure)
        }
        return try await GeneratedCaptureWriter.writeJPEG(into: session, device: device, exposure: exposure, accent: (0.76, 0.18, 0.19))
    }
}

public struct NikonSDKBackend: VendorCameraBackend {
    public let vendor: CameraVendor = .nikon
    public let integrationStatus = "Nikon bridge seam matches the Canon path: private wrapper binary or target plugs into the public protocol, preserving licensed SDK isolation while supporting more production-like discovery, connection ownership, capture transfer, and reconnect behavior."

    public init() {}

    public func discoverMockDevices() async -> [CameraDevice] {
        guard let bridge = VendorBridgeRegistry.bridge(for: .nikon),
              let devices = try? await bridge.discoverDevices(),
              devices.isEmpty == false else { return [] }
        let profile = await bridge.profile()
        return devices.map {
            CameraDevice(
                modelName: $0.modelName,
                manufacturer: $0.manufacturer,
                serialNumber: $0.serialNumber,
                batteryLevel: $0.batteryLevel,
                vendor: .nikon,
                capabilities: .init(
                    supportsRemoteCapture: profile.supportsRemoteCapture,
                    supportsLiveView: profile.supportsLiveView,
                    supportsExposureControl: profile.supportsExposureControl,
                    supportsFileEvents: profile.supportsFileEvents,
                    notes: integrationStatus + " " + profile.operationalNotes
                )
            )
        }
    }

    public func connect(to device: CameraDevice) async throws -> CameraDevice {
        if let bridge = VendorBridgeRegistry.bridge(for: .nikon) {
            try await bridge.connect(serialNumber: device.serialNumber)
        }
        try await Task.sleep(for: .milliseconds(140))
        var connected = device
        connected.isConnected = true
        return connected
    }

    public func disconnect(from device: CameraDevice) async {
        if let bridge = VendorBridgeRegistry.bridge(for: .nikon) {
            try? await bridge.disconnect(serialNumber: device.serialNumber)
        }
    }

    public func capture(into session: CaptureSession, device: CameraDevice, exposure: CameraExposureState) async throws -> CaptureResult {
        if let bridge = VendorBridgeRegistry.bridge(for: .nikon), let captureURL = session.folderURL(for: .capture) {
            let payload = try await bridge.triggerCapture(into: captureURL)
            return CaptureResult(asset: CaptureAsset(sessionID: session.id, fileURL: payload.fileURL, capturedAt: .now, cameraName: payload.cameraName, lensName: payload.lensName, iso: payload.iso, shutterSpeed: payload.shutterSpeed, aperture: payload.aperture), exposure: exposure)
        }
        return try await GeneratedCaptureWriter.writeJPEG(into: session, device: device, exposure: exposure, accent: (0.88, 0.72, 0.14))
    }
}

public struct MockPTPBackend: VendorCameraBackend {
    public let vendor: CameraVendor = .genericPTP
    public let integrationStatus = "Runnable open scaffold using generated JPEG captures and protocol-based control flow. Replace with ImageCaptureCore/PTP or vendor SDK event transport when available."

    public init() {}

    public func discoverMockDevices() async -> [CameraDevice] { [] }

    public func connect(to device: CameraDevice) async throws -> CameraDevice {
        try await Task.sleep(for: .milliseconds(80))
        var connected = device
        connected.isConnected = true
        return connected
    }

    public func disconnect(from device: CameraDevice) async {}

    public func capture(into session: CaptureSession, device: CameraDevice, exposure: CameraExposureState) async throws -> CaptureResult {
        try await GeneratedCaptureWriter.writeJPEG(into: session, device: device, exposure: exposure, accent: (0.16, 0.48, 0.94))
