public actor CompositeCameraDriver: CameraDriver {
    public private(set) var connectionState: CameraConnectionState = .disconnected
    public private(set) var connectedDevice: CameraDevice?
    public private(set) var exposureState: CameraExposureState = .init()
    public private(set) var driverNotes: String = "Mock/PTP scaffold active"
    public private(set) var healthSnapshot: TetherHealthSnapshot = .init()

    private let backends: [CameraVendor: VendorCameraBackend]
    private var lastDiscovery: [CameraDevice] = []
    private var liveViewTask: Task<Void, Never>?

    public init(
        canon: VendorCameraBackend = CanonEDSDKBackend(),
        nikon: VendorCameraBackend = NikonSDKBackend(),
        generic: VendorCameraBackend = MockPTPBackend()
    ) {
        self.backends = [
            .canon: canon,
            .nikon: nikon,
            .genericPTP: generic,
            .mock: generic
        ]
    }

    public func discoverDevices() async throws -> [CameraDevice] {
        transition(to: .discovering, level: .nominal, summary: "Scanning for tether-capable cameras")
        do {
            try await Task.sleep(for: .milliseconds(220))
            var discovered: [CameraDevice] = []
            for backend in uniqueBackends() {
                let devices = await backend.discoverMockDevices()
                discovered.append(contentsOf: devices)
            }
            let devices = Array(Dictionary(grouping: discovered, by: { "\($0.vendor.rawValue)|\($0.serialNumber)" }).values.compactMap(\.first))
                .sorted { lhs, rhs in
                    (lhs.manufacturer, lhs.modelName, lhs.serialNumber) < (rhs.manufacturer, rhs.modelName, rhs.serialNumber)
                }
            lastDiscovery = devices
            transition(to: .ready, level: devices.isEmpty ? .degraded : .nominal, summary: devices.isEmpty ? "No cameras discovered" : "Discovered \(devices.count) camera(s)")
            return devices
        } catch {
            record(error: error, state: .error, summary: "Camera discovery failed")
            throw error
        }
    }

    public func connect(to device: CameraDevice) async throws {
        guard let backend = backends[device.vendor] else {
            throw NSError(domain: "CaptureDesk.CompositeCameraDriver", code: 404, userInfo: [NSLocalizedDescriptionKey: "No backend registered for \(device.vendor.rawValue)"])
        }

        if let existing = connectedDevice, existing.serialNumber != device.serialNumber {
            await disconnectCurrentDevice(reason: "Switching to \(device.modelName)")
        }

        transition(to: .connecting, level: .nominal, device: device, summary: "Connecting to \(device.modelName)")
        do {
            let connected = try await backend.connect(to: device)
            connectedDevice = connected
            driverNotes = backend.integrationStatus + "\nCapabilities: \(capabilitySummary(for: connected.capabilities))"
            transition(to: .connected, level: .nominal, device: connected, summary: "Transport connected to \(connected.modelName)")
            transition(to: .ready, level: .nominal, device: connected, summary: "Ready for capture")
        } catch {
            record(error: error, state: .error, device: device, summary: "Camera connect failed")
            throw error
        }
    }

    public func disconnect() async {
        await disconnectCurrentDevice(reason: "Disconnected camera session")
    }

    public func capture(into session: CaptureSession) async throws -> CaptureResult {
        guard let connectedDevice else {
            let error = NSError(domain: "CaptureDesk.CompositeCameraDriver", code: 400, userInfo: [NSLocalizedDescriptionKey: "No active camera connection."])
            record(error: error, state: .error, summary: "Capture requested without an active device")
            throw error
        }
        guard let backend = backends[connectedDevice.vendor] else {
            let error = NSError(domain: "CaptureDesk.CompositeCameraDriver", code: 404, userInfo: [NSLocalizedDescriptionKey: "No backend registered for \(connectedDevice.vendor.rawValue)"])
            record(error: error, state: .error, device: connectedDevice, summary: "Capture backend missing")
            throw error
        }
        transition(to: .capturing, level: .nominal, device: connectedDevice, summary: "Triggering capture")
        do {
            let result = try await backend.capture(into: session, device: connectedDevice, exposure: exposureState)
            healthSnapshot.lastCaptureAt = .now
            transition(to: .ready, level: .nominal, device: connectedDevice, summary: "Capture completed: \(result.asset.fileURL.lastPathComponent)")
            return result
        } catch {
            record(error: error, state: .error, device: connectedDevice, summary: "Capture failed")
            throw error
        }
    }

    // MARK: - Live View

    public func startLiveView(frameHandler: @escaping @Sendable (CGImage) -> Void) async throws {
        guard let connectedDevice, connectedDevice.capabilities.supportsLiveView else {
            // Run mock live view for demo / devices that don't support it yet
            liveViewTask = Task {
                var frame = 0
                while !Task.isCancelled {
                    if let image = MockLiveViewGenerator.makeFrame(frame: frame) {
                        frameHandler(image)
                    }
                    frame += 1
                    try? await Task.sleep(for: .milliseconds(67))  // ~15 fps
                }
            }
            return
        }
        // Real vendor live view would call the vendor SDK here;
        // for now fall through to mock even for supported devices
        liveViewTask = Task {
            var frame = 0
            while !Task.isCancelled {
                if let image = MockLiveViewGenerator.makeFrame(frame: frame, label: connectedDevice.modelName) {
                    frameHandler(image)
                }
                frame += 1
                try? await Task.sleep(for: .milliseconds(67))
            }
        }
    }

    public func stopLiveView() async {
        liveViewTask?.cancel()
        liveViewTask = nil
    }

    private func uniqueBackends() -> [VendorCameraBackend] {
        var seen: Set<CameraVendor> = []
        return backends.values.filter { backend in
            guard seen.contains(backend.vendor) == false else { return false }
            seen.insert(backend.vendor)
            return true
        }
    }

    private func disconnectCurrentDevice(reason: String) async {
        if let device = connectedDevice, let backend = backends[device.vendor] {
            await backend.disconnect(from: device)
        }
        connectedDevice = nil
        transition(to: .disconnected, level: .nominal, device: nil, summary: reason)
    }

    private func transition(to state: CameraConnectionState, level: TetherHealthLevel, device: CameraDevice? = nil, summary: String) {
        connectionState = state
        if let device {
            healthSnapshot.activeVendor = device.vendor
            healthSnapshot.activeCameraName = device.modelName
        } else if state == .disconnected {
            healthSnapshot.activeVendor = nil
            healthSnapshot.activeCameraName = nil
        }
        healthSnapshot.state = state
        healthSnapshot.level = level
        healthSnapshot.lastStateChangeAt = .now
        healthSnapshot.diagnosticsSummary = summary
        if level != .faulted {
            healthSnapshot.lastError = nil
        }
    }

    private func record(error: Error, state: CameraConnectionState, device: CameraDevice? = nil, summary: String) {
        transition(to: state, level: .faulted, device: device, summary: summary)
        healthSnapshot.lastError = error.localizedDescription
        driverNotes = [driverNotes, "Last error: \(error.localizedDescription)"].filter { $0.isEmpty == false }.joined(separator: "\n")
    }

    private func capabilitySummary(for capabilities: CameraCapabilitySet) -> String {
        let items = [
            capabilities.supportsRemoteCapture ? "remote capture" : nil,
            capabilities.supportsLiveView ? "live view" : nil,
            capabilities.supportsExposureControl ? "exposure control" : nil,
            capabilities.supportsFileEvents ? "file events" : nil
        ].compactMap { $0 }
        return items.isEmpty ? "none" : items.joined(separator: ", ")
    }
}

// MARK: - Mock Live View Frame Generator

enum MockLiveViewGenerator {
    static func makeFrame(frame: Int, label: String = "Live View") -> CGImage? {
        let width = 1920, height = 1280
        let colorSpace = CGColorSpace(name: CGColorSpace.sRGB)!
        guard let ctx = CGContext(data: nil, width: width, height: height,
                                   bitsPerComponent: 8, bytesPerRow: width * 4,
                                   space: colorSpace,
                                   bitmapInfo: CGImageAlphaInfo.premultipliedLast.rawValue) else { return nil }

        // Animated background — slow pan & brightness pulse
        let t = Double(frame) / 30.0
        let brightness = CGFloat(0.08 + sin(t * 0.7) * 0.02)
        ctx.setFillColor(CGColor(red: brightness * 0.6, green: brightness * 0.7, blue: brightness, alpha: 1))
        ctx.fill(CGRect(x: 0, y: 0, width: width, height: height))

        // Studio grid lines
        ctx.setStrokeColor(CGColor(gray: 1, alpha: 0.06))
        ctx.setLineWidth(1)
        for x in stride(from: 0, through: width, by: width / 3) {
            ctx.move(to: CGPoint(x: x, y: 0)); ctx.addLine(to: CGPoint(x: x, y: height))
        }
        for y in stride(from: 0, through: height, by: height / 3) {
            ctx.move(to: CGPoint(x: 0, y: y)); ctx.addLine(to: CGPoint(x: width, y: y))
        }
        ctx.strokePath()

        // Focus peaking strip (simulated)
        let stripY = Int(CGFloat(height) * 0.45 + sin(t * 1.2) * CGFloat(height) * 0.04)
        ctx.setStrokeColor(CGColor(red: 1, green: 0.2, blue: 0.2, alpha: 0.55))
        ctx.setLineWidth(2)
        ctx.move(to: CGPoint(x: 0, y: stripY)); ctx.addLine(to: CGPoint(x: width, y: stripY))
        ctx.strokePath()

        // Center subject placeholder (circle + cross)
        let cx = CGFloat(width) / 2, cy = CGFloat(height) / 2
        let r: CGFloat = 180
        ctx.setStrokeColor(CGColor(gray: 1, alpha: 0.25))
        ctx.setLineWidth(1)
        ctx.strokeEllipse(in: CGRect(x: cx - r, y: cy - r, width: r * 2, height: r * 2))
        ctx.move(to: CGPoint(x: cx - r * 0.3, y: cy)); ctx.addLine(to: CGPoint(x: cx + r * 0.3, y: cy))
        ctx.move(to: CGPoint(x: cx, y: cy - r * 0.3)); ctx.addLine(to: CGPoint(x: cx, y: cy + r * 0.3))
        ctx.strokePath()

        // HUD overlay — bottom strip
        ctx.setFillColor(CGColor(gray: 0, alpha: 0.60))
        ctx.fill(CGRect(x: 0, y: 0, width: width, height: 52))

        // Framing: label text via bitmap encoding
        let hudText = "\(label)  |  1/125  f/2.8  ISO 400  |  LIVE"
        let textData = Data(hudText.utf8)
        for (i, byte) in textData.prefix(120).enumerated() {
            let v = CGFloat(byte) / 255.0
            ctx.setFillColor(CGColor(red: 0.2, green: 0.9, blue: 0.5, alpha: 0.8))
            ctx.fill(CGRect(x: 20 + i * 13, y: 14, width: 6, height: Int(v * 24) + 6))
        }

        return ctx.makeImage()
    }
}

enum GeneratedCaptureWriter {
    static func writeJPEG(into session: CaptureSession, device: CameraDevice, exposure: CameraExposureState, accent: (CGFloat, CGFloat, CGFloat)) async throws -> CaptureResult {
        guard let captureURL = session.folderURL(for: .capture) else {
            throw NSError(domain: "CaptureDesk.GeneratedCaptureWriter", code: 404, userInfo: [NSLocalizedDescriptionKey: "Capture folder missing from session."])
        }

        try FileManager.default.createDirectory(at: captureURL, withIntermediateDirectories: true)
        try await Task.sleep(for: .milliseconds(180))

        let timestamp = ISO8601DateFormatter().string(from: .now).replacingOccurrences(of: ":", with: "-")
        let filename = "CAP_\(device.vendor.rawValue.uppercased())_\(timestamp).jpg"
        let fileURL = uniqueFileURL(in: captureURL, preferredName: filename)
        try makeJPEG(at: fileURL, title: device.modelName, accent: accent, exposure: exposure)

        let asset = CaptureAsset(
            sessionID: session.id,
            fileURL: fileURL,
            capturedAt: .now,
            cameraName: device.modelName,
            lensName: device.vendor == .canon ? "RF 24-70mm f/2.8L" : (device.vendor == .nikon ? "NIKKOR Z 24-70mm f/2.8 S" : "Studio Prime 80mm"),
            iso: exposure.iso,
            shutterSpeed: exposure.shutterSpeed,
            aperture: Double(exposure.aperture.replacingOccurrences(of: "f/", with: "")) ?? 2.8
        )

        return CaptureResult(asset: asset, exposure: exposure)
    }

    private static func uniqueFileURL(in directory: URL, preferredName: String) -> URL {
        let candidate = directory.appendingPathComponent(preferredName)
        guard FileManager.default.fileExists(atPath: candidate.path) else { return candidate }

        let base = candidate.deletingPathExtension().lastPathComponent
        let ext = candidate.pathExtension
        for index in 1...999 {
            let next = directory.appendingPathComponent("\(base)-\(index)").appendingPathExtension(ext)
            if FileManager.default.fileExists(atPath: next.path) == false {
                return next
            }
        }
        return directory.appendingPathComponent(UUID().uuidString).appendingPathExtension(ext)
    }

    private static func makeJPEG(at url: URL, title: String, accent: (CGFloat, CGFloat, CGFloat), exposure: CameraExposureState) throws {
        let width = 2400
        let height = 1600
        let colorSpace = CGColorSpace(name: CGColorSpace.sRGB)!
        guard let context = CGContext(data: nil, width: width, height: height, bitsPerComponent: 8, bytesPerRow: width * 4, space: colorSpace, bitmapInfo: CGImageAlphaInfo.premultipliedLast.rawValue) else {
            throw NSError(domain: "CaptureDesk.GeneratedCaptureWriter", code: 500, userInfo: [NSLocalizedDescriptionKey: "Failed to create bitmap context"])
        }

        let base = CGColor(red: accent.0, green: accent.1, blue: accent.2, alpha: 1)
        let dark = CGColor(red: accent.0 * 0.2, green: accent.1 * 0.2, blue: accent.2 * 0.25, alpha: 1)
        context.setFillColor(dark)
        context.fill(CGRect(x: 0, y: 0, width: width, height: height))

        for index in 0..<12 {
            let alpha = CGFloat(index + 1) / 14.0
            context.setFillColor(base.copy(alpha: alpha * 0.12) ?? base)
            context.fillEllipse(in: CGRect(x: 120 + index * 120, y: 220 + index * 40, width: 900, height: 900))
        }

        context.setStrokeColor(CGColor(gray: 1, alpha: 0.22))
        context.setLineWidth(6)
        context.stroke(CGRect(x: 60, y: 60, width: width - 120, height: height - 120))

        let bandHeight = 180
        context.setFillColor(CGColor(gray: 0.06, alpha: 0.86))
        context.fill(CGRect(x: 0, y: 0, width: width, height: bandHeight))

        let metadata = "\(title)  •  ISO \(exposure.iso)  •  \(exposure.shutterSpeed)  •  \(exposure.aperture)"
        let data = Data(metadata.utf8)
        for (offset, byte) in data.prefix(800).enumerated() {
            let value = CGFloat(byte) / 255.0
            context.setFillColor(CGColor(red: value, green: 1 - value, blue: 0.72, alpha: 0.85))
            context.fill(CGRect(x: 80 + (offset * 8), y: 72, width: 5, height: 44 + Int(value * 44)))
        }

        guard let image = context.makeImage() else {
            throw NSError(domain: "CaptureDesk.GeneratedCaptureWriter", code: 501, userInfo: [NSLocalizedDescriptionKey: "Failed to create CGImage"])
        }
        guard let destination = CGImageDestinationCreateWithURL(url as CFURL, UTType.jpeg.identifier as CFString, 1, nil) else {
            throw NSError(domain: "CaptureDesk.GeneratedCaptureWriter", code: 502, userInfo: [NSLocalizedDescriptionKey: "Failed to create image destination"])
        }
        CGImageDestinationAddImage(destination, image, [kCGImageDestinationLossyCompressionQuality: 0.92] as CFDictionary)
        guard CGImageDestinationFinalize(destination) else {
            throw NSError(domain: "CaptureDesk.GeneratedCaptureWriter", code: 503, userInfo: [NSLocalizedDescriptionKey: "Failed to finalize image destination"])
        }
    }
}

