import Foundation
import CaptureDeskCore

public enum VendorSDKStatus: String, Codable, Sendable {
    case notConfigured
    case wrapperOnly
    case sdkAvailable
}

public struct VendorSDKConfiguration: Hashable, Codable, Sendable {
    public var vendor: CameraVendor
    public var wrapperRoot: URL
    public var headersPath: URL?
    public var librariesPath: URL?
    public var frameworkSearchPaths: [String]
    public var linkerFlags: [String]
    public var bridgeExecutablePath: URL?
    public var sdkRoot: URL?
    public var environment: [String: String]
    public var requestTimeoutSeconds: Double
    public var status: VendorSDKStatus
    public var notes: String

    public init(
        vendor: CameraVendor,
        wrapperRoot: URL,
        headersPath: URL? = nil,
        librariesPath: URL? = nil,
        frameworkSearchPaths: [String] = [],
        linkerFlags: [String] = [],
        bridgeExecutablePath: URL? = nil,
        sdkRoot: URL? = nil,
        environment: [String: String] = [:],
        requestTimeoutSeconds: Double = 15,
        status: VendorSDKStatus = .notConfigured,
        notes: String = ""
    ) {
        self.vendor = vendor
        self.wrapperRoot = wrapperRoot
        self.headersPath = headersPath
        self.librariesPath = librariesPath
        self.frameworkSearchPaths = frameworkSearchPaths
        self.linkerFlags = linkerFlags
        self.bridgeExecutablePath = bridgeExecutablePath
        self.sdkRoot = sdkRoot
        self.environment = environment
        self.requestTimeoutSeconds = requestTimeoutSeconds
        self.status = status
        self.notes = notes
    }
}

public struct VendorBridgeProfile: Hashable, Codable, Sendable {
    public var connectionTransport: String
    public var supportsRemoteCapture: Bool
    public var supportsLiveView: Bool
    public var supportsExposureControl: Bool
    public var supportsFileEvents: Bool
    public var supportsReconnect: Bool
    public var commandVersion: Int
    public var operationalNotes: String

    public init(
        connectionTransport: String,
        supportsRemoteCapture: Bool = true,
        supportsLiveView: Bool = false,
        supportsExposureControl: Bool = true,
        supportsFileEvents: Bool = false,
        supportsReconnect: Bool = true,
        commandVersion: Int = 1,
        operationalNotes: String = ""
    ) {
        self.connectionTransport = connectionTransport
        self.supportsRemoteCapture = supportsRemoteCapture
        self.supportsLiveView = supportsLiveView
        self.supportsExposureControl = supportsExposureControl
        self.supportsFileEvents = supportsFileEvents
        self.supportsReconnect = supportsReconnect
        self.commandVersion = commandVersion
        self.operationalNotes = operationalNotes
    }
}

public struct VendorCapturePayload: Hashable, Codable, Sendable {
    public var fileURL: URL
    public var cameraName: String
    public var lensName: String
    public var iso: Int
    public var shutterSpeed: String
    public var aperture: Double

    public init(fileURL: URL, cameraName: String, lensName: String, iso: Int, shutterSpeed: String, aperture: Double) {
        self.fileURL = fileURL
        self.cameraName = cameraName
        self.lensName = lensName
        self.iso = iso
        self.shutterSpeed = shutterSpeed
        self.aperture = aperture
    }
}

public protocol VendorSDKBridge: Sendable {
    var vendor: CameraVendor { get }
    var configuration: VendorSDKConfiguration { get }
    func profile() async -> VendorBridgeProfile
    func discoverDevices() async throws -> [VendorDiscoveredCamera]
    func connect(serialNumber: String) async throws
    func disconnect(serialNumber: String) async throws
    func triggerCapture(into folderURL: URL) async throws -> VendorCapturePayload
}

public struct VendorDiscoveredCamera: Hashable, Codable, Sendable {
    public var modelName: String
    public var manufacturer: String
    public var serialNumber: String
    public var batteryLevel: Int

    public init(modelName: String, manufacturer: String, serialNumber: String, batteryLevel: Int) {
        self.modelName = modelName
        self.manufacturer = manufacturer
        self.serialNumber = serialNumber
        self.batteryLevel = batteryLevel
    }
}

public enum VendorBridgeRegistry {
    public static func bridge(for vendor: CameraVendor) -> VendorSDKBridge? {
        switch vendor {
        case .canon:
            return PrivateSDKConfigLoader.loadBridge(for: .canon)
        case .nikon:
            return PrivateSDKConfigLoader.loadBridge(for: .nikon)
        case .sony, .fujifilm, .genericPTP, .mock:
            return nil
        }
    }
}

public enum PrivateSDKConfigLoader {
    public static func loadBridge(for vendor: CameraVendor, fileManager: FileManager = .default) -> VendorSDKBridge? {
        let configURL = AppPaths.defaultRootDirectory(fileManager: fileManager)
            .appendingPathComponent("PrivateSDK")
            .appendingPathComponent("\(vendor.rawValue).json")

        guard
            fileManager.fileExists(atPath: configURL.path),
            let data = try? Data(contentsOf: configURL),
            let configuration = try? JSONDecoder().decode(VendorSDKConfiguration.self, from: data)
        else {
            return nil
        }

        if let bridgeExecutablePath = configuration.bridgeExecutablePath,
           fileManager.isExecutableFile(atPath: bridgeExecutablePath.path) {
            return CLIVendorBridge(configuration: configuration)
        }

        return PlaceholderVendorBridge(configuration: configuration)
    }
}

public struct PlaceholderVendorBridge: VendorSDKBridge {
    public let configuration: VendorSDKConfiguration
    public var vendor: CameraVendor { configuration.vendor }

    public init(configuration: VendorSDKConfiguration) {
        self.configuration = configuration
    }

    public func profile() async -> VendorBridgeProfile {
        VendorBridgeProfile(
            connectionTransport: "placeholder",
            supportsRemoteCapture: false,
            supportsLiveView: false,
            supportsExposureControl: false,
            supportsFileEvents: false,
            supportsReconnect: false,
            operationalNotes: "Configured wrapper path exists in runtime settings, but the executable bridge is not installed yet."
        )
    }

    public func discoverDevices() async throws -> [VendorDiscoveredCamera] { [] }

    public func connect(serialNumber: String) async throws {
        throw NSError(domain: "CaptureDesk.PlaceholderVendorBridge", code: 1001, userInfo: [NSLocalizedDescriptionKey: "Private \(vendor.rawValue.capitalized) SDK wrapper not installed. Expected wrapper at \(configuration.wrapperRoot.path)"])
    }

    public func disconnect(serialNumber: String) async throws {}

    public func triggerCapture(into folderURL: URL) async throws -> VendorCapturePayload {
        throw NSError(domain: "CaptureDesk.PlaceholderVendorBridge", code: 1002, userInfo: [NSLocalizedDescriptionKey: "Private \(vendor.rawValue.capitalized) SDK wrapper not installed. Cannot capture into \(folderURL.path)"])
    }
}

public struct CLIVendorBridge: VendorSDKBridge {
    public let configuration: VendorSDKConfiguration
    public var vendor: CameraVendor { configuration.vendor }

    public init(configuration: VendorSDKConfiguration) {
        self.configuration = configuration
    }

    public func profile() async -> VendorBridgeProfile {
        do {
            let response: BridgeProfileResponse = try await run(BridgeProfileRequest(vendor: vendor))
            return response.profile
        } catch {
            return VendorBridgeProfile(
                connectionTransport: "cli",
                supportsRemoteCapture: true,
                supportsLiveView: false,
                supportsExposureControl: true,
                supportsFileEvents: false,
                supportsReconnect: true,
                operationalNotes: "Profile request failed: \(error.localizedDescription)"
            )
        }
    }

    public func discoverDevices() async throws -> [VendorDiscoveredCamera] {
        let response: BridgeDiscoverResponse = try await run(BridgeDiscoverRequest(vendor: vendor))
        return response.devices
    }

    public func connect(serialNumber: String) async throws {
        let ack: BridgeAckResponse = try await run(BridgeConnectRequest(command: .connect, vendor: vendor, serialNumber: serialNumber))
        if !ack.ok {
            let msg = ack.error ?? ack.message ?? "Connect failed"
            throw NSError(domain: "CaptureDesk.CLIVendorBridge", code: 2003, userInfo: [NSLocalizedDescriptionKey: msg])
        }
    }

    public func disconnect(serialNumber: String) async throws {
        let ack: BridgeAckResponse = try await run(BridgeConnectRequest(command: .disconnect, vendor: vendor, serialNumber: serialNumber))
        if !ack.ok {
            let msg = ack.error ?? ack.message ?? "Disconnect failed"
            throw NSError(domain: "CaptureDesk.CLIVendorBridge", code: 2004, userInfo: [NSLocalizedDescriptionKey: msg])
        }
    }

    public func triggerCapture(into folderURL: URL) async throws -> VendorCapturePayload {
        let response: BridgeCaptureResponse = try await run(BridgeCaptureRequest(command: .capture, vendor: vendor, folderURL: folderURL))
        return response.payload
    }

    private func run<Request: Encodable, Response: Decodable>(_ request: Request) async throws -> Response {
        guard configuration.bridgeExecutablePath != nil else {
            throw NSError(domain: "CaptureDesk.CLIVendorBridge", code: 2001,
                          userInfo: [NSLocalizedDescriptionKey: "No bridge executable configured for \(vendor.rawValue)"])
        }
        let conn = BridgeConnectionRegistry.connection(for: configuration)
        // Run blocking I/O on a detached thread so we never block the cooperative pool.
        return try await Task.detached(priority: .userInitiated) {
            try conn.execute(request)
        }.value
    }
}

// MARK: - Persistent Bridge Connection

/// Long-lived bridge process that stays alive for the app session.
/// Keeping the process alive holds the MAID3 session open, which prevents
/// ptpcamerad from reclaiming the USB device between commands.
/// An NSLock serializes commands so only one is in-flight at a time.
private final class BridgeConnection: @unchecked Sendable {
    private var process: Process?
    private var stdinHandle: FileHandle?
    private var stdoutFd: Int32 = -1
    private let lock = NSLock()
    private let configuration: VendorSDKConfiguration

    init(configuration: VendorSDKConfiguration) {
        self.configuration = configuration
    }

    func execute<Request: Encodable, Response: Decodable>(_ request: Request) throws -> Response {
        lock.lock()
        defer { lock.unlock() }
        try ensureRunning()
        guard let sin = stdinHandle, stdoutFd >= 0 else {
            throw bridgeError("No bridge process running")
        }
        var data = try JSONEncoder().encode(request)
        data.append(0x0A) // newline delimiter
        try sin.write(contentsOf: data)
        let line = try readLine()
        do {
            return try JSONDecoder().decode(Response.self, from: line)
        } catch {
            let body = String(data: line, encoding: .utf8) ?? "<non-utf8>"
            throw bridgeError("Failed to decode bridge response: \(body)")
        }
    }

    private func ensureRunning() throws {
        guard let p = process, p.isRunning else { try spawn(); return }
    }

    private func spawn() throws {
        guard let execURL = configuration.bridgeExecutablePath else {
            throw bridgeError("No bridge executable configured for \(configuration.vendor.rawValue)")
        }
        // Kill any stale bridge process from a previous session that may be holding
        // the MAID3 module exclusively — only one process can open the module at a time.
        let killer = Process()
        killer.executableURL = URL(fileURLWithPath: "/usr/bin/pkill")
        killer.arguments = ["-9", execURL.lastPathComponent]
        try? killer.run()
        killer.waitUntilExit()
        Thread.sleep(forTimeInterval: 1.0)
        let p = Process()
        p.executableURL = execURL
        var env = ProcessInfo.processInfo.environment
        env.merge(configuration.environment) { _, new in new }
        env["CAPTUREDESK_VENDOR"] = configuration.vendor.rawValue
        if let sdkRoot = configuration.sdkRoot?.path { env["CAPTUREDESK_SDK_ROOT"] = sdkRoot }
        p.environment = env
        p.qualityOfService = .userInitiated
        let inPipe = Pipe()
        let outPipe = Pipe()
        p.standardInput = inPipe
        p.standardOutput = outPipe
        p.standardError = Pipe()
        try p.run()
        process = p
        stdinHandle = inPipe.fileHandleForWriting
        stdoutFd = outPipe.fileHandleForReading.fileDescriptor
    }

    private func readLine() throws -> Data {
        var result = Data()
        var byte: UInt8 = 0
        while true {
            let n = withUnsafeMutablePointer(to: &byte) { Darwin.read(stdoutFd, $0, 1) }
            if n <= 0 { break }
            if byte == UInt8(ascii: "\n") { break }
            result.append(byte)
        }
        guard !result.isEmpty else {
            // Process died — clear state so next call respawns
            process = nil
            stdinHandle = nil
            stdoutFd = -1
            throw bridgeError("Bridge process closed connection unexpectedly")
        }
        return result
    }

    private func bridgeError(_ msg: String) -> NSError {
        NSError(domain: "CaptureDesk.CLIVendorBridge", code: 2001,
                userInfo: [NSLocalizedDescriptionKey: msg])
    }

    deinit {
        if let sin = stdinHandle { try? sin.write(contentsOf: Data("{\"command\":\"quit\"}\n".utf8)) }
        process?.terminate()
    }
}

// One persistent connection per vendor, shared for the process lifetime.
private enum BridgeConnectionRegistry {
    private static var connections: [CameraVendor: BridgeConnection] = [:]
    private static let lock = NSLock()

    static func connection(for configuration: VendorSDKConfiguration) -> BridgeConnection {
        lock.lock()
        defer { lock.unlock() }
        if let existing = connections[configuration.vendor] { return existing }
        let c = BridgeConnection(configuration: configuration)
        connections[configuration.vendor] = c
        return c
    }
}

