import Foundation
import CaptureDeskCore
import CaptureDeskVendorSupport

// ---------------------------------------------------------------------------
// MARK: - Canon Bridge CLI
//
// Implements the CaptureDesk vendor bridge JSON protocol over stdin/stdout.
// Current backend: gphoto2 (open-source PTP library).
//
// EDSDK upgrade path:
//   Replace the gphoto2 shell calls in each command handler with
//   EDSDK C API calls compiled into this binary. The JSON protocol
//   on stdin/stdout is unchanged — AppState/CompositeCameraDriver never
//   need to know which SDK is underneath.
//
//   Required EDSDK entry points per command:
//     discover  → EdsGetCameraList / EdsCameraList iteration
//     connect   → EdsOpenSession
//     capture   → EdsSendCommand(EDS_CMD_TakePicture) + EdsDownloadFile
//     disconnect→ EdsCloseSession
// ---------------------------------------------------------------------------

// MARK: - Process helpers

let gphoto2Path: String = {
    for path in ["/opt/homebrew/bin/gphoto2", "/usr/local/bin/gphoto2", "/usr/bin/gphoto2"] {
        if FileManager.default.isExecutableFile(atPath: path) { return path }
    }
    return "gphoto2"
}()

@discardableResult
func runProcess(_ executable: String, _ args: [String], timeoutSeconds: TimeInterval = 20) throws -> (stdout: String, stderr: String, status: Int32) {
    let proc = Process()
    proc.executableURL = URL(fileURLWithPath: executable)
    proc.arguments = args
    let outPipe = Pipe()
    let errPipe = Pipe()
    proc.standardOutput = outPipe
    proc.standardError = errPipe
    try proc.run()

    // Enforce timeout
    let timer = DispatchWorkItem { proc.terminate() }
    DispatchQueue.global().asyncAfter(deadline: .now() + timeoutSeconds, execute: timer)
    proc.waitUntilExit()
    timer.cancel()

    let out = String(data: outPipe.fileHandleForReading.readDataToEndOfFile(), encoding: .utf8) ?? ""
    let err = String(data: errPipe.fileHandleForReading.readDataToEndOfFile(), encoding: .utf8) ?? ""
    return (out, err, proc.terminationStatus)
}

// MARK: - IO

func writeResponse<T: Encodable>(_ value: T) throws {
    let data = try JSONEncoder().encode(value)
    FileHandle.standardOutput.write(data)
}

func fail(_ message: String) -> Never {
    let msg = message + "\n"
    FileHandle.standardError.write(Data(msg.utf8))
    exit(1)
}

// MARK: - Dispatch

let inputData = FileHandle.standardInput.readDataToEndOfFile()
let decoder = JSONDecoder()

private struct GenericRequest: Decodable {
    var command: BridgeCommand
    var vendor: CameraVendor
}

guard let generic = try? decoder.decode(GenericRequest.self, from: inputData) else {
    fail("Failed to decode bridge request from stdin")
}

switch generic.command {

// -------------------------------------------------------------------------
// MARK: profile
// -------------------------------------------------------------------------
case .profile:
    let profile = VendorBridgeProfile(
        connectionTransport: "gphoto2",
        supportsRemoteCapture: true,
        supportsLiveView: false,
        supportsExposureControl: false,
        supportsFileEvents: false,
        supportsReconnect: true,
        commandVersion: 1,
        operationalNotes: "gphoto2 PTP backend. Replace with EDSDK for production."
    )
    try writeResponse(BridgeProfileResponse(profile: profile))

// -------------------------------------------------------------------------
// MARK: discover
// -------------------------------------------------------------------------
case .discover:
    let result = try? runProcess(gphoto2Path, ["--auto-detect"], timeoutSeconds: 10)
    let output = result?.stdout ?? ""

    var devices: [VendorDiscoveredCamera] = []
    let allLines = output.components(separatedBy: "\n")

    // Determine column split from the header line ("Model ... Port ...")
    var portColumnStart = 32  // default observed value
    if let header = allLines.first, let portRange = header.range(of: "Port") {
        portColumnStart = header.distance(from: header.startIndex, to: portRange.lowerBound)
    }

    let lines = allLines.dropFirst(2)  // skip header + separator

    for line in lines {
        let trimmed = line.trimmingCharacters(in: .whitespaces)
        guard !trimmed.isEmpty, !trimmed.hasPrefix("-") else { continue }

        guard line.count > portColumnStart else { continue }
        let modelEnd = line.index(line.startIndex, offsetBy: portColumnStart)
        let model = String(line[line.startIndex..<modelEnd]).trimmingCharacters(in: .whitespaces)
        let portPart = String(line[modelEnd...]).trimmingCharacters(in: .whitespaces)

        guard !model.isEmpty else { continue }

        // Try to get serial number from camera config
        var serial: String = portPart
            .replacingOccurrences(of: "usb:", with: "USB-")
            .replacingOccurrences(of: ",", with: "-")

        if !portPart.isEmpty {
            let snResult = try? runProcess(gphoto2Path, ["--port", portPart, "--get-config", "/main/status/serialnumber"], timeoutSeconds: 5)
            if let snOut = snResult?.stdout {
                for snLine in snOut.components(separatedBy: "\n") {
                    if snLine.contains("Current:") {
                        let value = snLine
                            .replacingOccurrences(of: "Current:", with: "")
                            .trimmingCharacters(in: .whitespaces)
                        if !value.isEmpty && value != "0" {
                            serial = value
                            break
                        }
                    }
                }
            }
        }

        let manufacturer: String
        if model.lowercased().hasPrefix("canon") { manufacturer = "Canon" }
        else if model.lowercased().hasPrefix("nikon") { manufacturer = "Nikon" }
        else if model.lowercased().hasPrefix("sony") { manufacturer = "Sony" }
        else if model.lowercased().hasPrefix("fuji") { manufacturer = "Fujifilm" }
        else { manufacturer = "Unknown" }

        devices.append(VendorDiscoveredCamera(
            modelName: model,
            manufacturer: manufacturer,
            serialNumber: serial,
            batteryLevel: 0
        ))
    }

    try writeResponse(BridgeDiscoverResponse(devices: devices))

// -------------------------------------------------------------------------
// MARK: connect
// -------------------------------------------------------------------------
case .connect:
    // Verify the camera responds to a lightweight command.
    // --abilities is fast and doesn't require full PTP session init.
    let result = try? runProcess(gphoto2Path, ["--auto-detect"], timeoutSeconds: 8)
    let ok = (result?.status ?? 1) == 0
    try writeResponse(BridgeAckResponse(ok: ok, message: ok ? "Camera reachable" : "Camera not found"))

// -------------------------------------------------------------------------
// MARK: disconnect
// -------------------------------------------------------------------------
case .disconnect:
    try writeResponse(BridgeAckResponse(ok: true, message: "Disconnected"))

// -------------------------------------------------------------------------
// MARK: capture
// -------------------------------------------------------------------------
case .capture:
    guard let captureReq = try? decoder.decode(BridgeCaptureRequest.self, from: inputData) else {
        fail("Failed to decode capture request")
    }

    let folder = captureReq.folderURL
    try FileManager.default.createDirectory(at: folder, withIntermediateDirectories: true)

    let ts = Int(Date.now.timeIntervalSince1970)
    // %C → camera-native extension (CR3, CR2, NEF, JPG, etc.)
    let filenameTemplate = "CAP_\(ts).%C"
    let filepathTemplate = folder.appendingPathComponent(filenameTemplate).path

    let (captureOut, captureErr, captureStatus) = (try? runProcess(
        gphoto2Path,
        ["--capture-image-and-download", "--filename", filepathTemplate, "--force-overwrite"],
        timeoutSeconds: 30
    )) ?? ("", "", 1)

    // Parse the actual saved path from gphoto2 output:
    // "Saving file as /path/CAP_1234567890.CR3"
    var downloadedURL: URL? = nil
    let allOutput = captureOut + "\n" + captureErr
    for line in allOutput.components(separatedBy: "\n") {
        let lower = line.lowercased()
        if lower.contains("saving file as") || lower.contains("new file") {
            // Extract path after "as " or the last whitespace-delimited token
            let parts = line.trimmingCharacters(in: .whitespaces).components(separatedBy: " ")
            if let last = parts.last, last.hasPrefix("/") {
                let candidate = URL(fileURLWithPath: last)
                if FileManager.default.fileExists(atPath: candidate.path) {
                    downloadedURL = candidate
                    break
                }
            }
        }
    }

    // Fallback: scan folder for newest image file created in the last 60s
    if downloadedURL == nil {
        let imageExtensions = Set(["cr3", "cr2", "nef", "arw", "jpg", "jpeg", "tif", "tiff"])
        let cutoff = Date.now.addingTimeInterval(-60)
        if let contents = try? FileManager.default.contentsOfDirectory(
            at: folder,
            includingPropertiesForKeys: [.contentModificationDateKey, .creationDateKey]
        ) {
            downloadedURL = contents
                .filter { imageExtensions.contains($0.pathExtension.lowercased()) }
                .compactMap { url -> (URL, Date)? in
                    let mdate = (try? url.resourceValues(forKeys: [.contentModificationDateKey]).contentModificationDate) ?? .distantPast
                    return mdate >= cutoff ? (url, mdate) : nil
                }
                .sorted { $0.1 > $1.1 }
                .first?.0
        }
    }

    guard let fileURL = downloadedURL else {
        fail("Capture failed (gphoto2 exit \(captureStatus)). Output: \(allOutput.prefix(400))")
    }

    let fileSize = (try? FileManager.default.attributesOfItem(atPath: fileURL.path)[.size] as? Int) ?? 0
    if fileSize == 0 {
        fail("Captured file is 0 bytes: \(fileURL.path)")
    }

    // Build payload — camera name from auto-detect output
    var cameraName = "Canon EOS Camera"
    if let detectOut = (try? runProcess(gphoto2Path, ["--auto-detect"], timeoutSeconds: 5))?.stdout {
        let detectLines = detectOut.components(separatedBy: "\n")
        var split = 32
        if let hdr = detectLines.first, let r = hdr.range(of: "Port") {
            split = hdr.distance(from: hdr.startIndex, to: r.lowerBound)
        }
        for line in detectLines.dropFirst(2) {
            let trimmed = line.trimmingCharacters(in: .whitespaces)
            guard !trimmed.isEmpty, !trimmed.hasPrefix("-"), line.count > split else { continue }
            let idx = line.index(line.startIndex, offsetBy: split)
            cameraName = String(line[line.startIndex..<idx]).trimmingCharacters(in: .whitespaces)
            break
        }
    }

    let payload = VendorCapturePayload(
        fileURL: fileURL,
        cameraName: cameraName,
        lensName: "",
        iso: 100,
        shutterSpeed: "1/125",
        aperture: 2.8
    )
    try writeResponse(BridgeCaptureResponse(payload: payload))
}

