266	    /// Polls for a camera every 5 s for up to 90 s. Used after initial discovery finds nothing.
267	    private func startDiscoveryRetry() {
268	        discoveryRetryTask?.cancel()
269	        discoveryRetryTask = Task { [weak self] in
270	            let maxAttempts = 18  // 18 × 5 s = 90 s
271	            for attempt in 1...maxAttempts {
272	                try? await Task.sleep(for: .seconds(5))
273	                guard let self, !Task.isCancelled else { return }
274	
275	                do {
276	                    let cameras = try await self.cameraDriver.discoverDevices()
277	                    guard let first = cameras.first else {
278	                        if attempt % 3 == 0 {
279	                            self.statusMessage = "Still looking for camera… (\(attempt * 5)s)"
280	                        }
281	                        continue
282	                    }
283	                    self.connectedCameras = cameras
284	                    self.activeCamera = first
285	                    try await self.cameraDriver.connect(to: first)
286	                    self.exposureState = await self.cameraDriver.exposureState
287	                    await self.refreshTetherRuntime()
288	                    self.statusMessage = "Connected to \(first.modelName)"
289	                    return
290	                } catch {
291	                    // Suppress per-attempt errors; only report after timeout
292	                }
293	            }
