663	    // MARK: - Helpers
664	
665	    private func uniqueImportDestination(in folder: URL, originalName: String) -> URL {
666	        let candidate = folder.appendingPathComponent(originalName)
667	        guard FileManager.default.fileExists(atPath: candidate.path) else { return candidate }
668	        let base = candidate.deletingPathExtension().lastPathComponent
669	        let ext = candidate.pathExtension
670	        for index in 1...999 {
671	            let next = folder.appendingPathComponent("\(base)-import-\(index)").appendingPathExtension(ext)
672	            if FileManager.default.fileExists(atPath: next.path) == false { return next }
673	        }
674	        return folder.appendingPathComponent(UUID().uuidString).appendingPathExtension(ext)
675	    }
