import Foundation
import Observation
import AppKit
import CoreGraphics
import CaptureDeskCore
import CaptureDeskTethering
import CaptureDeskSessions
import CaptureDeskEditor

@MainActor
@Observable
final class AppState {
    var sessions: [CaptureSession] = []
    var selectedSession: CaptureSession?
    var assets: [CaptureAsset] = []
    var selectedAsset: CaptureAsset?
    var currentRecipe: EditRecipe?
    var previewSummary: String = "No preview rendered"
    var connectedCameras: [CameraDevice] = []
    var activeCamera: CameraDevice?
    var exposureState: CameraExposureState = .init()
    var statusMessage: String = "Ready"
    var driverNotes: String = ""
    var tetherHealth: TetherHealthSnapshot = .init()
    var tetherEvents: [TetherSessionEvent] = []
    var assetFilter: AssetFilter = .all
    var sortOrder: AssetSortOrder = .capturedDescending
    var lastExportJob: ExportJob?
    var importInFlight: Bool = false
    var compareModeEnabled: Bool = false
    var histogramSummary: [Double] = []

    // Live View
    var liveViewActive: Bool = false
    var liveViewFrame: CGImage?

    // Local adjustment selection
    var selectedLocalAdjustmentID: UUID?
    var activeMaskTool: LocalMaskType = .radial
    var brushModeActive: Bool = false

    // Clipboard / Undo
    var copiedAdjustments: AdjustmentState?
    private var undoStack: [AdjustmentState] = []
    private var redoStack: [AdjustmentState] = []
    var canUndo: Bool { undoStack.isEmpty == false }
    var canRedo: Bool { redoStack.isEmpty == false }

    // Presets
    var presets: [AdjustmentPreset] = AdjustmentPreset.builtIns
    private let presetRepository = PresetRepository()

    // Batch export
    var isExporting: Bool = false
    var exportProgress: Double = 0

    // Session editing
    var editingSession: CaptureSession?

    // Crop / brush overlay state (UI only, not persisted)
    var cropModeActive: Bool = false
    var brushSize: Double = 0.04        // normalized radius 0–1
    var brushFeather: Double = 0.5
    var brushEraseMode: Bool = false
    var activeBrushLayerID: UUID?
    var previewNativeSize: CGSize = CGSize(width: 4000, height: 2667)  // updated on each render

    private let sessionRepository = SessionRepository()
    private let assetRepository = CaptureAssetRepository()
    private let recipeRepository = EditRecipeRepository()
    private let renderPipeline = CoreImageRenderPipeline()
    private let cameraDriver = RecoveringCameraDriver(base: CompositeCameraDriver())
    private var watchTask: Task<Void, Never>?
    private var renderDebounce: Task<Void, Never>?
    private var discoveryRetryTask: Task<Void, Never>?

    init() {
        reloadSessions()
        loadCustomPresets()
        // Auto-discover on launch so tethering starts without user interaction.
        Task { [weak self] in
            try? await Task.sleep(for: .seconds(1))
            self?.discoverCameras()
        }
    }

    // MARK: - Filtered & Sorted Assets

    var filteredAssets: [CaptureAsset] {
        let filtered: [CaptureAsset]
        switch assetFilter {
        case .all:     filtered = assets
        case .picks:   filtered = assets.filter(\.isPicked)
        case .rated:   filtered = assets.filter { $0.rating.rawValue > 0 }
        case .tagged:  filtered = assets.filter { $0.colorTag != .none }
        case .rejects: filtered = assets.filter { $0.rating == .rejected }
        }
        return sorted(filtered)
    }

    private func sorted(_ list: [CaptureAsset]) -> [CaptureAsset] {
        switch sortOrder {
        case .capturedDescending: return list.sorted { $0.capturedAt > $1.capturedAt }
        case .capturedAscending:  return list.sorted { $0.capturedAt < $1.capturedAt }
        case .nameAscending:      return list.sorted { $0.fileURL.lastPathComponent < $1.fileURL.lastPathComponent }
        case .ratingDescending:   return list.sorted { $0.rating.rawValue > $1.rating.rawValue }
        }
    }

    // MARK: - Session Management

    func reloadSessions() {
        sessions = sessionRepository.loadSessions()
        if selectedSession == nil { selectedSession = sessions.first }
        if let selectedSession { loadAssets(for: selectedSession) }
    }

    func createSeedSessionIfNeeded() {
        guard sessions.isEmpty else { return }
        do {
            let session = try sessionRepository.createSession(named: "Demo Session", clientName: "Studio Client", projectName: "Spring Lookbook")
            selectedSession = session
            reloadSessions()
            statusMessage = "Created demo session"
        } catch {
            statusMessage = "Failed to create demo session: \(error.localizedDescription)"
        }
    }

    func createSession() {
        do {
            let name = "Session \(Date.now.formatted(date: .abbreviated, time: .omitted))"
            let session = try sessionRepository.createSession(named: name, clientName: "New Client", projectName: "Untitled")
            selectedSession = session
            reloadSessions()
            statusMessage = "Created \(session.name)"
        } catch {
            statusMessage = "Session creation failed: \(error.localizedDescription)"
        }
    }

    func saveSessionEdits(_ session: CaptureSession) {
        do {
            try sessionRepository.update(session)
            if let idx = sessions.firstIndex(where: { $0.id == session.id }) {
                sessions[idx] = session
            }
            if selectedSession?.id == session.id { selectedSession = session }
            editingSession = nil
            statusMessage = "Session saved"
        } catch {
            statusMessage = "Session save failed: \(error.localizedDescription)"
        }
    }

    func revealSelectedSessionInFinder() {
        guard let selectedSession else { return }
        NSWorkspace.shared.activateFileViewerSelecting([selectedSession.rootURL])
    }

    // MARK: - Assets

    func importFiles(urls: [URL]) {
        guard let selectedSession, urls.isEmpty == false, let captureFolder = selectedSession.folderURL(for: .capture) else {
            statusMessage = "Select a session before importing"
            return
        }
        importInFlight = true
        defer { importInFlight = false }
        do {
            for sourceURL in urls {
                let destination = uniqueImportDestination(in: captureFolder, originalName: sourceURL.lastPathComponent)
                if FileManager.default.fileExists(atPath: destination.path) { continue }
                try FileManager.default.copyItem(at: sourceURL, to: destination)
            }
            assets = try assetRepository.importNewFilesIfNeeded(for: selectedSession)
            statusMessage = "Imported \(urls.count) file(s)"
        } catch {
            statusMessage = "Import failed: \(error.localizedDescription)"
        }
    }

    func loadAssets(for session: CaptureSession) {
        selectedSession = session
        Task {
            await cameraDriver.prepare(session: session)
            await refreshTetherRuntime()
        }
        do {
            assets = try assetRepository.importNewFilesIfNeeded(for: session)
        } catch {
            assets = assetRepository.loadAssets(for: session)
            statusMessage = "Asset load warning: \(error.localizedDescription)"
        }
        selectedAsset = assets.first
        refreshRecipeForSelection()
        startWatchingSelectedSession()
    }

    func selectAsset(_ asset: CaptureAsset) {
        selectedAsset = asset
        refreshRecipeForSelection()
    }

    func nextAsset() {
        let list = filteredAssets
        guard let current = selectedAsset, let idx = list.firstIndex(where: { $0.id == current.id }) else {
            selectedAsset = filteredAssets.first
            refreshRecipeForSelection()
            return
        }
        let next = min(idx + 1, list.count - 1)
        selectAsset(list[next])
    }

    func previousAsset() {
        let list = filteredAssets
        guard let current = selectedAsset, let idx = list.firstIndex(where: { $0.id == current.id }) else {
            selectedAsset = filteredAssets.first
            refreshRecipeForSelection()
            return
        }
        let prev = max(idx - 1, 0)
        selectAsset(list[prev])
    }

    // MARK: - Camera

    func discoverCameras() {
        discoveryRetryTask?.cancel()
        statusMessage = "Scanning for cameras…"
        Task { await runDiscovery() }
    }

    private func runDiscovery() async {
        await cameraDriver.prepare(session: selectedSession)
        do {
            let cameras = try await cameraDriver.discoverDevices()
            connectedCameras = cameras
            if let first = cameras.first {
                activeCamera = first
                statusMessage = "Found \(first.modelName) — connecting…"
                do {
                    try await cameraDriver.connect(to: first)
                    exposureState = await cameraDriver.exposureState
                    await refreshTetherRuntime()
                    statusMessage = "Connected to \(first.modelName)"
                    discoveryRetryTask = nil
                } catch {
                    await refreshTetherRuntime()
                    statusMessage = "Found \(first.modelName) — connect failed: \(error.localizedDescription)"
                    startDiscoveryRetry()
                }
            } else {
                await refreshTetherRuntime()
                statusMessage = "No camera found. Make sure the camera is on and USB is connected, then tap Discover."
                startDiscoveryRetry()
            }
        } catch {
            await refreshTetherRuntime()
            statusMessage = "Discovery failed: \(error.localizedDescription)"
            startDiscoveryRetry()
        }
    }

    /// Polls for a camera every 5 s for up to 90 s. Used after initial discovery finds nothing.
    private func startDiscoveryRetry() {
        discoveryRetryTask?.cancel()
        discoveryRetryTask = Task { [weak self] in
            let maxAttempts = 18  // 18 × 5 s = 90 s
            for attempt in 1...maxAttempts {
                try? await Task.sleep(for: .seconds(5))
                guard let self, !Task.isCancelled else { return }

                do {
                    let cameras = try await self.cameraDriver.discoverDevices()
                    guard let first = cameras.first else {
                        if attempt % 3 == 0 {
                            self.statusMessage = "Still looking for camera… (\(attempt * 5)s)"
                        }
                        continue
                    }
                    self.connectedCameras = cameras
                    self.activeCamera = first
                    try await self.cameraDriver.connect(to: first)
                    self.exposureState = await self.cameraDriver.exposureState
                    await self.refreshTetherRuntime()
                    self.statusMessage = "Connected to \(first.modelName)"
                    return
                } catch {
                    // Suppress per-attempt errors; only report after timeout
                }
            }
            self?.statusMessage = "Camera not found after 90 s. Check USB connection and camera power."
        }
    }

    func connectCamera(_ camera: CameraDevice) {
        Task {
            await cameraDriver.prepare(session: selectedSession)
            do {
                try await cameraDriver.connect(to: camera)
                activeCamera = camera
                await refreshTetherRuntime()
                statusMessage = "Switched to \(camera.modelName)"
            } catch {
                await refreshTetherRuntime()
                statusMessage = "Camera connect failed: \(error.localizedDescription)"
            }
        }
    }

    func triggerCapture() {
        guard let selectedSession else {
            statusMessage = "Create or select a session first"
            return
        }
        Task {
            await cameraDriver.prepare(session: selectedSession)
            do {
                let result = try await cameraDriver.capture(into: selectedSession)
                assets = try assetRepository.append(result, to: selectedSession)
                selectedAsset = assets.first
                exposureState = result.exposure
                await refreshTetherRuntime()
                refreshRecipeForSelection()
                statusMessage = "Captured \(result.asset.fileURL.lastPathComponent)"
            } catch {
                await refreshTetherRuntime()
                statusMessage = "Capture failed: \(error.localizedDescription)"
            }
        }
    }

    // MARK: - Live View

    func startLiveView() {
        guard !liveViewActive else { return }
        liveViewActive = true
        Task {
            try? await cameraDriver.startLiveView { [weak self] frame in
                Task { @MainActor [weak self] in
                    self?.liveViewFrame = frame
                }
            }
        }
    }

    func stopLiveView() {
        liveViewActive = false
        liveViewFrame = nil
        Task { await cameraDriver.stopLiveView() }
    }

    // MARK: - Local Adjustments

    func addLocalAdjustment(type: LocalMaskType) {
        guard currentRecipe != nil else { return }
        let adj = LocalAdjustment(
            label: "\(type.label) \((currentRecipe?.localAdjustments.count ?? 0) + 1)",
            maskType: type
        )
        updateRecipe { $0.localAdjustments.append(adj) }
        selectedLocalAdjustmentID = adj.id
    }

    func removeLocalAdjustment(id: UUID) {
        updateRecipe { $0.localAdjustments.removeAll { $0.id == id } }
        if selectedLocalAdjustmentID == id { selectedLocalAdjustmentID = nil }
    }

    func updateLocalAdjustment(id: UUID, transform: (inout LocalAdjustment) -> Void) {
        updateRecipe { recipe in
            guard let idx = recipe.localAdjustments.firstIndex(where: { $0.id == id }) else { return }
            transform(&recipe.localAdjustments[idx])
        }
    }

    // MARK: - Recipe / Editing

    func refreshRecipeForSelection() {
        guard let selectedAsset else {
            currentRecipe = nil
            previewSummary = "No asset selected"
            return
        }
        currentRecipe = recipeRepository.loadRecipe(for: selectedAsset)
        scheduleRender()
    }

    func renderPreview() {
        guard let selectedAsset, let currentRecipe, let selectedSession else {
            previewSummary = "No preview available"
            return
        }
        Task {
            do {
                let preview = try await renderPipeline.renderPreview(for: selectedAsset, recipe: currentRecipe)
                previewSummary = preview.summary
                histogramSummary = preview.histogramBins
                if let sz = preview.nativeSize { previewNativeSize = sz }
                var updatedAsset = selectedAsset
                updatedAsset.previewURL = preview.previewURL
                updatedAsset.thumbnailURL = preview.thumbnailURL
                assets = try assetRepository.update(updatedAsset, in: selectedSession)
                self.selectedAsset = assets.first(where: { $0.id == updatedAsset.id })
            } catch {
                histogramSummary = []
                previewSummary = "Render failed: \(error.localizedDescription)"
            }
        }
    }

    private func scheduleRender() {
        renderDebounce?.cancel()
        renderDebounce = Task {
            try? await Task.sleep(for: .milliseconds(120))
            guard !Task.isCancelled else { return }
            self.renderPreview()
        }
    }

    func updateRecipe(_ update: (inout EditRecipe) -> Void) {
        guard var recipe = currentRecipe, let selectedAsset else { return }

        // Push current state to undo stack before modifying
        pushUndo(recipe.adjustments)

        update(&recipe)
        currentRecipe = recipe
        do {
            try recipeRepository.saveRecipe(recipe, for: selectedAsset)
            scheduleRender()
        } catch {
            statusMessage = "Failed to save recipe: \(error.localizedDescription)"
        }
    }

    func updateSelectedAsset(_ update: (inout CaptureAsset) -> Void) {
        guard let selectedSession, var asset = selectedAsset else { return }
        update(&asset)
        do {
            assets = try assetRepository.update(asset, in: selectedSession)
            selectedAsset = assets.first(where: { $0.id == asset.id })
        } catch {
            statusMessage = "Metadata update failed: \(error.localizedDescription)"
        }
    }

    // MARK: - Undo / Redo

    private func pushUndo(_ state: AdjustmentState) {
        undoStack.append(state)
        if undoStack.count > 60 { undoStack.removeFirst() }
        redoStack.removeAll()
    }

    func undo() {
        guard let prev = undoStack.popLast(), var recipe = currentRecipe, let selectedAsset else { return }
        redoStack.append(recipe.adjustments)
        recipe.adjustments = prev
        currentRecipe = recipe
        try? recipeRepository.saveRecipe(recipe, for: selectedAsset)
        scheduleRender()
    }

    func redo() {
        guard let next = redoStack.popLast(), var recipe = currentRecipe, let selectedAsset else { return }
        undoStack.append(recipe.adjustments)
        recipe.adjustments = next
        currentRecipe = recipe
        try? recipeRepository.saveRecipe(recipe, for: selectedAsset)
        scheduleRender()
    }

    // MARK: - Clipboard

    func copyAdjustments() {
        copiedAdjustments = currentRecipe?.adjustments
        if copiedAdjustments != nil { statusMessage = "Adjustments copied" }
    }

    func pasteAdjustments() {
        guard let adj = copiedAdjustments else {
            statusMessage = "Nothing to paste"
            return
        }
        updateRecipe { $0.adjustments = adj }
        statusMessage = "Adjustments pasted"
    }

    func resetAdjustments() {
        updateRecipe { recipe in
            recipe.adjustments = AdjustmentState()
        }
        statusMessage = "Adjustments reset"
    }

    // MARK: - Rating / Metadata

    func cycleRating(_ rating: CaptureRating) {
        updateSelectedAsset { $0.rating = rating }
        statusMessage = rating == .rejected ? "Rejected" : (rating == .unrated ? "Unrated" : "\(rating.rawValue) star")
    }

    func cycleColorTag(_ tag: ColorTag) {
        updateSelectedAsset { $0.colorTag = tag }
    }

    func togglePicked() {
        updateSelectedAsset { $0.isPicked.toggle() }
        statusMessage = selectedAsset?.isPicked == true ? "Picked" : "Unpicked"
    }

    // MARK: - Export

    func exportSelectedAsset() {
        guard let selectedAsset, let currentRecipe, let selectedSession else {
            statusMessage = "Select an asset before exporting"
            return
        }
        Task {
            do {
                let job = try await renderPipeline.export(asset: selectedAsset, recipe: currentRecipe, to: selectedSession)
                lastExportJob = job
                statusMessage = "Exported to \(job.destinationURL.lastPathComponent)"
            } catch {
                statusMessage = "Export failed: \(error.localizedDescription)"
            }
        }
    }

    func batchExportPicks() {
        guard let selectedSession else {
            statusMessage = "No active session"
            return
        }
        let picks = assets.filter(\.isPicked)
        guard picks.isEmpty == false else {
            statusMessage = "No picks to export"
            return
        }
        isExporting = true
        exportProgress = 0
        Task {
            let total = Double(picks.count)
            var exported = 0
            for asset in picks {
                let recipe = recipeRepository.loadRecipe(for: asset)
                do {
                    _ = try await renderPipeline.export(asset: asset, recipe: recipe, to: selectedSession)
                    exported += 1
                } catch {
                    // continue with remaining
                }
                exportProgress = Double(exported) / total
            }
            isExporting = false
            exportProgress = 0
            statusMessage = "Batch exported \(exported) pick(s)"
        }
    }

    func batchExportAll() {
        guard let selectedSession else {
            statusMessage = "No active session"
            return
        }
        let allAssets = filteredAssets
        guard allAssets.isEmpty == false else {
            statusMessage = "No assets to export"
            return
        }
        isExporting = true
        exportProgress = 0
        Task {
            let total = Double(allAssets.count)
            var exported = 0
            for asset in allAssets {
                let recipe = recipeRepository.loadRecipe(for: asset)
                do {
                    _ = try await renderPipeline.export(asset: asset, recipe: recipe, to: selectedSession)
                    exported += 1
                } catch {
                    // continue
                }
                exportProgress = Double(exported) / total
            }
            isExporting = false
            exportProgress = 0
            statusMessage = "Batch exported \(exported) asset(s)"
        }
    }

    // MARK: - Presets

    private func loadCustomPresets() {
        let custom = presetRepository.loadCustomPresets()
        presets = AdjustmentPreset.builtIns + custom
    }

    func savePreset(name: String) {
        guard let adj = currentRecipe?.adjustments else {
            statusMessage = "No adjustments to save"
            return
        }
        let preset = AdjustmentPreset(name: name, adjustments: adj)
        presets.append(preset)
        try? presetRepository.saveCustomPresets(presets)
        statusMessage = "Preset '\(name)' saved"
    }

    func applyPreset(_ preset: AdjustmentPreset) {
        updateRecipe { $0.adjustments = preset.adjustments }
        statusMessage = "Applied '\(preset.name)'"
    }

    func deletePreset(_ preset: AdjustmentPreset) {
        guard preset.isBuiltIn == false else { return }
        presets.removeAll { $0.id == preset.id }
        try? presetRepository.saveCustomPresets(presets)
        statusMessage = "Deleted '\(preset.name)'"
    }

    // MARK: - Tether Watch

    private func startWatchingSelectedSession() {
        watchTask?.cancel()
        guard let session = selectedSession else { return }
        watchTask = Task { [weak self] in
            while Task.isCancelled == false {
                try? await Task.sleep(for: .seconds(2))
                guard let self else { return }
                await self.refreshSessionWatch(sessionID: session.id)
            }
        }
    }

    private func refreshSessionWatch(sessionID: UUID) async {
        guard let selectedSession, selectedSession.id == sessionID else { return }
        do {
            let previousCount = assets.count
            let refreshed = try assetRepository.importNewFilesIfNeeded(for: selectedSession)
            if refreshed.count != previousCount {
                assets = refreshed
                if selectedAsset == nil {
                    selectedAsset = refreshed.first
                    refreshRecipeForSelection()
                }
                statusMessage = "Imported \(max(refreshed.count - previousCount, 0)) new capture(s)"
            }
        } catch {
            statusMessage = "Watch import failed: \(error.localizedDescription)"
        }
    }

    private func refreshTetherRuntime() async {
        driverNotes = await cameraDriver.driverNotes
        tetherHealth = await cameraDriver.healthSnapshot
        tetherEvents = await cameraDriver.recentEvents(limit: 12)
    }

    // MARK: - Helpers

    private func uniqueImportDestination(in folder: URL, originalName: String) -> URL {
        let candidate = folder.appendingPathComponent(originalName)
        guard FileManager.default.fileExists(atPath: candidate.path) else { return candidate }
        let base = candidate.deletingPathExtension().lastPathComponent
        let ext = candidate.pathExtension
        for index in 1...999 {
            let next = folder.appendingPathComponent("\(base)-import-\(index)").appendingPathExtension(ext)
            if FileManager.default.fileExists(atPath: next.path) == false { return next }
        }
        return folder.appendingPathComponent(UUID().uuidString).appendingPathExtension(ext)
    }
}

