import Foundation
import ImageCaptureCore
import CoreGraphics
import ImageIO
import UniformTypeIdentifiers
import AVFoundation
import CaptureDeskCore

// MARK: - ICA Delegate Bridge (MainActor)

/// Handles all ImageCaptureCore delegate callbacks. Must stay on MainActor
/// because ICDeviceBrowser requires a run loop and calls delegates on the main thread.
@MainActor
final class ICABridge: NSObject, ICDeviceBrowserDelegate, ICCameraDeviceDelegate, ICDeviceDelegate {

    private let browser = ICDeviceBrowser()

    // Keyed by uuidString (or name fallback) — string keys are Sendable
    private(set) var discoveredCameras: [String: ICCameraDevice] = [:]
    private(set) var connectedCamera: ICCameraDevice?

    // Pending async bridges
    var discoveryCont: CheckedContinuation<[String: ICADeviceSnapshot], Never>?
    var captureCont: CheckedContinuation<URL, Error>?
    var pendingDownloadDir: URL?

    /// Called for every downloaded file — used for tethered watch mode (manual shutter presses).
    var liveCaptureSink: ((URL) -> Void)?

    override init() {
        super.init()
        browser.delegate = self
        // ICDeviceTypeMask must be OR'd with ICDeviceLocationTypeMask.
        // Camera (0x1) + Local/USB (0x100) + Bonjour/TCP-IP (0x400) + Bluetooth (0x800)
        // Without the location bits the browser silently finds nothing on macOS 26.
        let mask = 0x0001 | 0x0100 | 0x0200 | 0x0400 | 0x0800
        browser.browsedDeviceTypeMask = ICDeviceTypeMask(rawValue: UInt(mask))!
    }

    /// Call this after camera authorization is confirmed.
    func startBrowser() {
        // NEVER call browser.stop() here — it triggers a ptpcamerad "task name
        // port right" kernel bug on macOS 26 beta that permanently kills enumeration.
        if !browser.isBrowsing { browser.start() }
    }

    // MARK: - Discovery

    func startDiscovery(continuation: CheckedContinuation<[String: ICADeviceSnapshot], Never>) {
        // Cancel any previous leaked continuation before storing the new one.
        discoveryCont?.resume(returning: snapshots())
        discoveryCont = continuation

        // Return immediately if the always-on browser already found devices.
        if !discoveredCameras.isEmpty {
            continuation.resume(returning: snapshots())
            discoveryCont = nil
            return
        }

        // NEVER call browser.stop() here. On macOS 26 beta, stopping the browser
        // while ptpcamerad is starting up triggers "Unable to obtain a task name
        // port right" errors in icdd, which kills the enumeration permanently for
        // that app session.
        //
        // Strategy: keep the singleton browser alive. When ptpcamerad finishes
        // warming up (seconds after a daemon restart or app launch), it pushes the
        // already-connected camera into icdd, which fires didAdd to our running
        // browser. We just need to wait for that event — no restart required.
        if !browser.isBrowsing { browser.start() }

        // Kick off a TCC camera-permission request so the auth dialog appears if
        // the user hasn't approved it yet. Fire-and-forget.
        AVCaptureDevice.requestAccess(for: .video) { _ in }

        // 20-second patience window. Resolves early as soon as didAdd fires.
        let bridge = self
        Task { @MainActor in
            try? await Task.sleep(for: .seconds(20))
            if let cont = bridge.discoveryCont {
                cont.resume(returning: bridge.snapshots())
                bridge.discoveryCont = nil
            }
        }
    }

    func snapshots() -> [String: ICADeviceSnapshot] {
        discoveredCameras.mapValues { ICADeviceSnapshot(from: $0) }
    }

    /// Start ptpcamerad / icdd if stopped, then force a fresh browser scan.
    /// - launchctl kickstart (no -k): starts the service if stopped, no-op if running.
    ///   Avoids the SIP "operation not permitted" error from force-restart.
    /// - Browser stop+restart after a delay: safe here because by the time we restart
    ///   the daemons are already fully initialised (not mid-startup), so the
    ///   ptpcamerad "task name port right" race condition cannot occur.
    func kickICAdaemons() {
        runQuietly("/bin/sh", ["-c",
            "launchctl kickstart gui/$(id -u)/com.apple.ptpcamerad 2>/dev/null; " +
            "launchctl kickstart gui/$(id -u)/com.apple.icdd 2>/dev/null"
        ])
        // Give daemons 3 s to fully register the camera, then do a fresh browse.
        let bridge = self
        Task { @MainActor in
            try? await Task.sleep(for: .seconds(3))
            // Only restart if camera still hasn't appeared.
            guard bridge.discoveredCameras.isEmpty else { return }
            bridge.browser.stop()
            try? await Task.sleep(for: .milliseconds(500))
            bridge.browser.start()
        }
    }

    private func runQuietly(_ path: String, _ args: [String]) {
        let proc = Process()
        proc.executableURL = URL(fileURLWithPath: path)
        proc.arguments = args
        proc.standardOutput = Pipe()
        proc.standardError = Pipe()
        try? proc.run()
        // Fire and forget — results arrive via ICDeviceBrowserDelegate callbacks.
    }

    // MARK: - Connection

    func openSession(key: String) throws {
        guard let cam = discoveredCameras[key] else {
            throw NSError(domain: "ICADriver", code: 404, userInfo: [NSLocalizedDescriptionKey: "Camera '\(key)' not in ICA registry"])
        }
        connectedCamera = cam
        cam.delegate = self
        cam.requestOpenSession()
    }

    func closeSession() {
        connectedCamera?.requestCloseSession()
        connectedCamera = nil
    }

    // MARK: - Capture

    func triggerCapture(downloadTo dir: URL, continuation: CheckedContinuation<URL, Error>) {
        guard let cam = connectedCamera else {
            continuation.resume(throwing: NSError(domain: "ICADriver", code: 400,
                userInfo: [NSLocalizedDescriptionKey: "No camera connected for capture"]))
            return
        }
        captureCont = continuation
        pendingDownloadDir = dir
        cam.requestTakePicture()
    }

    // MARK: - ICDeviceBrowserDelegate

    nonisolated func deviceBrowser(_ browser: ICDeviceBrowser, didAdd device: ICDevice, moreComing: Bool) {
        MainActor.assumeIsolated {
            guard let cam = device as? ICCameraDevice else { return }
            let key = cam.uuidString ?? cam.name ?? cam.serialNumberString ?? UUID().uuidString
            discoveredCameras[key] = cam
            if !moreComing {
                discoveryCont?.resume(returning: snapshots())
                discoveryCont = nil
            }
        }
    }

    nonisolated func deviceBrowser(_ browser: ICDeviceBrowser, didRemove device: ICDevice, moreGoing: Bool) {
        MainActor.assumeIsolated {
            guard let cam = device as? ICCameraDevice else { return }
            let key = cam.uuidString ?? cam.name ?? cam.serialNumberString ?? ""
            discoveredCameras.removeValue(forKey: key)
            if connectedCamera === cam { connectedCamera = nil }
        }
    }

    nonisolated func deviceBrowserDidEnumerateLocalDevices(_ browser: ICDeviceBrowser) {
        MainActor.assumeIsolated {
            // Only resolve early if cameras were actually found on this enumeration.
            // If the list is empty (ptpcamerad not ready yet), leave the continuation
            // open — it will be resolved by didAdd when ptpcamerad catches up,
            // or by the 20-second timeout in startDiscovery.
            guard !discoveredCameras.isEmpty else { return }
            discoveryCont?.resume(returning: snapshots())
            discoveryCont = nil
        }
    }

    // MARK: - ICCameraDeviceDelegate

    /// A new file appeared on the camera — download it regardless of trigger source.
    nonisolated func cameraDevice(_ camera: ICCameraDevice, didAdd items: [ICCameraItem]) {
        MainActor.assumeIsolated {
            guard let file = items.compactMap({ $0 as? ICCameraFile }).last else { return }

            // Determine download directory: use pending dir (app-triggered) or a temp dir.
            let dir = pendingDownloadDir ?? FileManager.default.temporaryDirectory
                .appendingPathComponent("CaptureDesk_Tether", isDirectory: true)
            try? FileManager.default.createDirectory(at: dir, withIntermediateDirectories: true)

            let cont = captureCont
            let sink = liveCaptureSink
            captureCont = nil
            pendingDownloadDir = nil

            let destName = file.name ?? "capture_\(Int(Date.now.timeIntervalSince1970)).jpg"
            let options: [ICDownloadOption: Any] = [
                .downloadsDirectoryURL: dir,
                .saveAsFilename: destName,
                .overwrite: true,
                .deleteAfterSuccessfulDownload: false
            ]

            _ = file.requestDownload(options: options) { savedFilename, error in
                let url = dir.appendingPathComponent(savedFilename ?? destName)
                if let cont {
                    if let error { cont.resume(throwing: error) }
                    else { cont.resume(returning: url) }
                }
                if error == nil { sink?(url) }
            }
        }
    }

    nonisolated func cameraDevice(_ camera: ICCameraDevice, didRemove items: [ICCameraItem]) {}
    nonisolated func cameraDevice(_ camera: ICCameraDevice, didRenameItems items: [ICCameraItem]) {}
    nonisolated func cameraDeviceDidChangeCapability(_ camera: ICCameraDevice) {}

    // Required by ICCameraDeviceDelegate in macOS 13+
    nonisolated func cameraDevice(_ camera: ICCameraDevice,
                                   didReceiveThumbnail thumbnail: CGImage?,
                                   for item: ICCameraItem,
                                   error: (any Error)?) {}

    nonisolated func cameraDevice(_ camera: ICCameraDevice,
                                   didReceiveMetadata metadata: [AnyHashable: Any]?,
                                   for item: ICCameraItem,
                                   error: (any Error)?) {}

    nonisolated func cameraDevice(_ camera: ICCameraDevice, didReceivePTPEvent eventData: Data) {}
    nonisolated func deviceDidBecomeReady(withCompleteContentCatalog device: ICCameraDevice) {}
    nonisolated func cameraDeviceDidRemoveAccessRestriction(_ device: ICDevice) {}
    nonisolated func cameraDeviceDidEnableAccessRestriction(_ device: ICDevice) {}

    // MARK: - ICDeviceDelegate (required for session open/close callbacks)

    nonisolated func device(_ device: ICDevice, didOpenSessionWithError error: Error?) {
        if let error {
            MainActor.assumeIsolated {
                captureCont?.resume(throwing: error)
                captureCont = nil
            }
        }
    }

    nonisolated func device(_ device: ICDevice, didCloseSessionWithError error: Error?) {}
    nonisolated func didRemove(_ device: ICDevice) {}
}

// MARK: - Sendable Snapshot (safe to cross actor boundaries)

/// A Sendable snapshot of an ICCameraDevice's metadata.
struct ICADeviceSnapshot: Sendable {
    let key: String
    let name: String
    let serialNumber: String
    let batteryLevel: Int
    let batteryAvailable: Bool
    let canTakePicture: Bool

    init(from device: ICCameraDevice) {
        key = device.uuidString ?? device.name ?? device.serialNumberString ?? UUID().uuidString
        name = device.name ?? "Camera"
        serialNumber = device.serialNumberString ?? device.uuidString ?? UUID().uuidString
        batteryLevel = device.batteryLevelAvailable ? Int(device.batteryLevel) : -1
        batteryAvailable = device.batteryLevelAvailable
        canTakePicture = device.capabilities.contains(ICDeviceCapability.cameraDeviceCanTakePicture.rawValue)
    }
}

// MARK: - ICA Driver (Actor)

/// Real tethering driver backed by Apple's ImageCaptureCore.
/// Discovers all PTP/MTP/WiFi cameras (Canon, Nikon, Sony, Phase One, etc.)
/// without requiring any vendor SDK. Falls back to mock capture when no
/// physical camera is connected, so the app stays fully functional in development.
public actor ICADriver: CameraDriver {
    public private(set) var connectionState: CameraConnectionState = .disconnected
    public private(set) var connectedDevice: CameraDevice?
    public private(set) var exposureState: CameraExposureState = .init()
    public private(set) var driverNotes: String = "ImageCaptureCore bridge active — discovers Canon, Nikon, Sony, Phase One and all PTP/MTP cameras"
    public private(set) var healthSnapshot: TetherHealthSnapshot = .init()

    // Map our CameraDevice.id → ICA key (string, Sendable)
    private var icaKeyForID: [UUID: String] = [:]
    private var liveViewTask: Task<Void, Never>?
    // Kept current by capture(into:) so the live sink can route new files correctly.
    private var currentSession: CaptureSession?

    public init() {
        // Touch the singleton immediately so ICDeviceBrowser starts running at app launch.
        // It must be alive before ptpcamerad fires the "device added" event.
        Task { @MainActor in _ = ICABridgeSingleton.shared }
    }

    // MARK: - CameraDriver

    public func prepareSession(_ session: CaptureSession?) async {
        currentSession = session
    }

    /// Fire-and-forget kick of imagecaptured / icdd daemons. Works without root for the
    /// user-session service; system-service kick may silently fail but is worth trying.
    public func kickDaemons() async {
        await MainActor.run { ICABridgeSingleton.shared.kickDaemons() }
    }

    /// Returns cameras currently in the ICDeviceBrowser registry without any waiting.
    /// Empty when daemons haven't registered a device yet.
    public func peekDiscoveredDevices() async -> [CameraDevice] {
        let snaps: [String: ICADeviceSnapshot] = await MainActor.run {
            ICABridgeSingleton.shared.currentSnapshots()
        }
        guard !snaps.isEmpty else { return [] }
        return snaps.values.map { snap in
            let vendor = inferVendor(from: snap.name)
            let device = CameraDevice(
                modelName: snap.name,
                manufacturer: vendorDisplayName(vendor),
                serialNumber: snap.serialNumber,
                batteryLevel: snap.batteryLevel,
                isConnected: false,
                vendor: vendor,
                capabilities: .init(
                    supportsRemoteCapture: snap.canTakePicture,
                    supportsLiveView: false,
                    supportsExposureControl: false,
                    supportsFileEvents: true,
                    notes: "ImageCaptureCore"
                )
            )
            icaKeyForID[device.id] = snap.key
            return device
        }.sorted { $0.modelName < $1.modelName }
    }

    public func discoverDevices() async throws -> [CameraDevice] {
        connectionState = .discovering
        healthSnapshot = TetherHealthSnapshot(state: .discovering, level: .nominal,
            diagnosticsSummary: "Scanning via ImageCaptureCore…")

        // Ask the bridge to enumerate. We get back Sendable snapshots.
        let snapshots: [String: ICADeviceSnapshot] = await withCheckedContinuation { cont in
            Task { @MainActor in
                ICABridgeSingleton.shared.startDiscovery(continuation: cont)
            }
        }

        // Build our CameraDevice models
        let devices: [CameraDevice] = snapshots.values.map { snap in
            let vendor = inferVendor(from: snap.name)
            let device = CameraDevice(
                modelName: snap.name,
                manufacturer: vendorDisplayName(vendor),
                serialNumber: snap.serialNumber,
                batteryLevel: snap.batteryLevel,
                isConnected: false,
                vendor: vendor,
                capabilities: .init(
                    supportsRemoteCapture: snap.canTakePicture,
                    supportsLiveView: false,
                    supportsExposureControl: false,
                    supportsFileEvents: true,
                    notes: "ImageCaptureCore — real hardware tethering"
                )
            )
            icaKeyForID[device.id] = snap.key
            return device
        }
        .sorted { $0.modelName < $1.modelName }

        if devices.isEmpty {
            driverNotes = "No cameras found via ImageCaptureCore."
            connectionState = .ready
            healthSnapshot = TetherHealthSnapshot(state: .ready, level: .degraded,
                diagnosticsSummary: "No cameras found — connect a camera via USB")
        } else {
            driverNotes = "ICA found \(devices.count) physical camera(s):\n" +
                devices.map { "  • \($0.modelName) [\($0.serialNumber)]" }.joined(separator: "\n")
            connectionState = .ready
            healthSnapshot = TetherHealthSnapshot(state: .ready, level: .nominal,
                diagnosticsSummary: "\(devices.count) camera(s) available")
        }
        return devices
    }

    public func connect(to device: CameraDevice) async throws {
        connectionState = .connecting
        healthSnapshot.state = .connecting

        guard let key = icaKeyForID[device.id] else {
            throw NSError(domain: "ICADriver", code: 404, userInfo: [
                NSLocalizedDescriptionKey: "'\(device.modelName)' not found in ICA registry. Run Discover Cameras first."
            ])
        }

        try await MainActor.run {
            try ICABridgeSingleton.shared.openSession(key: key)
        }

        // Allow session open handshake to complete
        try await Task.sleep(for: .milliseconds(600))

        var updated = device
        updated.isConnected = true
        connectedDevice = updated
        connectionState = .ready
        healthSnapshot = TetherHealthSnapshot(
            state: .ready, level: .nominal,
            activeVendor: device.vendor,
            activeCameraName: device.modelName,
            diagnosticsSummary: "Connected to \(device.modelName) via ImageCaptureCore"
        )
        driverNotes = "Connected: \(device.modelName) (SN: \(device.serialNumber))\nUsing ImageCaptureCore PTP/MTP transport."

        // Wire live sink: any file added to the camera (manual shutter press)
        // is automatically imported into the active session (currentSession, set per-capture).
        let cameraName = device.modelName
        await MainActor.run {
            ICABridgeSingleton.shared.setLiveCaptureSink { [weak self] url in
                guard let self else { return }
                Task { await self.handleLiveFile(url, cameraName: cameraName) }
            }
        }
    }

    /// Called for every file downloaded from the camera (manual shutter or app-triggered).
    /// Moves the file into the active session's Capture folder so the 2-second watch loop
    /// in AppState picks it up automatically. Also reads EXIF to refresh exposureState.
    private func handleLiveFile(_ url: URL, cameraName: String) async {
        guard let session = currentSession,
              let captureFolder = session.folderURL(for: .capture) else { return }
        try? FileManager.default.createDirectory(at: captureFolder, withIntermediateDirectories: true)
        let dest = captureFolder.appendingPathComponent(url.lastPathComponent)
        // Move (same volume = instant rename; different = copy+delete).
        if (try? FileManager.default.moveItem(at: url, to: dest)) == nil {
            try? FileManager.default.copyItem(at: url, to: dest)
        }
        // Update exposure from the file's EXIF so the UI shows the correct camera settings.
        if let exif = exposureFromEXIF(at: dest) { exposureState = exif }
        healthSnapshot.lastCaptureAt = .now
    }

    /// Read shutter / aperture / ISO from ImageIO EXIF metadata.
    private func exposureFromEXIF(at url: URL) -> CameraExposureState? {
        guard let src = CGImageSourceCreateWithURL(url as CFURL, nil),
              let props = CGImageSourceCopyPropertiesAtIndex(src, 0, nil) as? [String: Any],
              let exif = props[kCGImagePropertyExifDictionary as String] as? [String: Any]
        else { return nil }

        var state = CameraExposureState()

        if let isoList = exif[kCGImagePropertyExifISOSpeedRatings as String] as? [Int],
           let iso = isoList.first {
            state.iso = iso
        }
        if let ev = exif[kCGImagePropertyExifExposureTime as String] as? Double, ev > 0 {
            if ev >= 1 {
                state.shutterSpeed = "\(Int(ev.rounded()))s"
            } else {
                state.shutterSpeed = "1/\(Int((1.0 / ev).rounded()))"
            }
        }
        if let fnum = exif[kCGImagePropertyExifFNumber as String] as? Double {
            state.aperture = String(format: "f/%.1f", fnum)
        }
        return state
    }

    public func disconnect() async {
        await MainActor.run { ICABridgeSingleton.shared.closeSession() }
        connectedDevice = nil
        connectionState = .disconnected
        healthSnapshot = TetherHealthSnapshot(state: .disconnected, level: .nominal,
            diagnosticsSummary: "Disconnected")
    }

    public func capture(into session: CaptureSession) async throws -> CaptureResult {
        currentSession = session          // keep live sink in sync
        guard let captureFolder = session.folderURL(for: .capture) else {
            throw NSError(domain: "ICADriver", code: 404, userInfo: [
                NSLocalizedDescriptionKey: "Session '\(session.name)' has no capture folder."
            ])
        }
        try FileManager.default.createDirectory(at: captureFolder, withIntermediateDirectories: true)

        connectionState = .capturing
        healthSnapshot.state = .capturing

        // Real ICA capture
        let fileURL: URL = try await withCheckedThrowingContinuation { cont in
            Task { @MainActor in
                ICABridgeSingleton.shared.triggerCapture(downloadTo: captureFolder, continuation: cont)
            }
        }

        connectionState = .ready
        healthSnapshot.state = .ready
        healthSnapshot.lastCaptureAt = .now

        // Refresh exposure from EXIF so the UI shows the correct camera settings.
        if let exif = exposureFromEXIF(at: fileURL) { exposureState = exif }

        let resourceValues = try? fileURL.resourceValues(forKeys: [.creationDateKey, .fileSizeKey])
        let asset = CaptureAsset(
            sessionID: session.id,
            fileURL: fileURL,
            capturedAt: resourceValues?.creationDate ?? .now,
            cameraName: connectedDevice?.modelName ?? "Camera",
            fileSize: resourceValues?.fileSize ?? 0
        )
        return CaptureResult(asset: asset, exposure: exposureState)
    }

    public func startLiveView(frameHandler: @escaping @Sendable (CGImage) -> Void) async throws {
        liveViewTask?.cancel()
        liveViewTask = Task {
            var frame = 0
            while !Task.isCancelled {
                if let img = MockLiveViewGenerator.makeFrame(
                    frame: frame,
                    label: connectedDevice?.modelName ?? "Live View"
                ) {
                    frameHandler(img)
                }
                frame += 1
                try? await Task.sleep(for: .milliseconds(67))
            }
        }
    }

    public func stopLiveView() async {
        liveViewTask?.cancel()
        liveViewTask = nil
    }

    // MARK: - USB presence detection

    /// Returns true if any PTP/Still-Image USB device (bInterfaceClass = 6) is visible
    /// in the IOKit device tree. This works even when ptpcamerad/icdd are not running.
    /// Used by AppState to decide whether to retry discovery vs. give up immediately.
    public static func hasPTPCameraOnUSB() -> Bool {
        let proc = Process()
        proc.executableURL = URL(fileURLWithPath: "/usr/sbin/ioreg")
        proc.arguments = ["-r", "-c", "IOUSBHostInterface", "-l"]
        let pipe = Pipe()
        proc.standardOutput = pipe
        proc.standardError = Pipe()    // discard stderr
        do { try proc.run() } catch { return false }
        proc.waitUntilExit()
        let output = String(data: pipe.fileHandleForReading.readDataToEndOfFile(), encoding: .utf8) ?? ""
        // bInterfaceClass 6 = USB Still Image (PTP/MTP). Also match known camera vendor IDs.
        return output.contains("\"bInterfaceClass\" = 6")
            || output.contains("\"idVendor\" = 1193")   // Canon
            || output.contains("\"idVendor\" = 1200")   // Nikon
            || output.contains("\"idVendor\" = 1356")   // Sony
    }

    // MARK: - Private helpers

    private func inferVendor(from name: String) -> CameraVendor {
        let n = name.lowercased()
        if n.contains("canon") { return .canon }
        if n.contains("nikon") { return .nikon }
        if n.contains("sony") { return .sony }
        if n.contains("fuji") { return .fujifilm }
        return .genericPTP
    }

    private func vendorDisplayName(_ vendor: CameraVendor) -> String {
        switch vendor {
        case .canon: return "Canon"
        case .nikon: return "Nikon"
        case .sony: return "Sony"
        case .fujifilm: return "Fujifilm"
        case .genericPTP: return "Camera"
        case .mock: return "CaptureDesk"
        }
    }
}

// MARK: - Singleton (keeps ICDeviceBrowser alive for the app lifetime)

/// Singleton so the ICDeviceBrowser stays running and accumulates devices.
@MainActor
final class ICABridgeSingleton {
    static let shared = ICABridgeSingleton()
    private let bridge = ICABridge()
    private init() {
        // Start the browser immediately at init so we never miss a device-added event.
        bridge.startBrowser()
    }

    func startDiscovery(continuation: CheckedContinuation<[String: ICADeviceSnapshot], Never>) {
        bridge.startDiscovery(continuation: continuation)
    }

    /// Instant snapshot of currently-known cameras — no waiting.
    /// Returns empty if the ICA registry is empty (daemons not ready yet).
    func currentSnapshots() -> [String: ICADeviceSnapshot] {
        bridge.snapshots()
    }

    /// Kick the ICA daemon chain. Fire-and-forget; results arrive via callbacks.
    func kickDaemons() {
        bridge.kickICAdaemons()
    }

    func openSession(key: String) throws {
        try bridge.openSession(key: key)
    }

    func closeSession() {
        bridge.closeSession()
    }

    func triggerCapture(downloadTo dir: URL, continuation: CheckedContinuation<URL, Error>) {
        bridge.triggerCapture(downloadTo: dir, continuation: continuation)
    }

    func setLiveCaptureSink(_ sink: ((URL) -> Void)?) {
        bridge.liveCaptureSink = sink
    }
}

