// PTP SetDevicePropValue(0xd110 = CaptureDestination, 0x00000002 = SDRAM/host)
// This tells the camera to buffer the image internally and transfer to the Mac
// instead of writing to a memory card — identical to how Capture One tethers.
func setSaveToHost(_ cam: ICCameraDevice) {
    guard cam.name?.lowercased().contains("canon") == true ||
          cam.uuidString != nil else { return }
    var command = Data(count: 6)
    command.withUnsafeMutableBytes { buf in
        buf.storeBytes(of: UInt16(0x1016).littleEndian, as: UInt16.self)  // SetDevicePropValue
        buf.storeBytes(of: UInt32(0xd110).littleEndian, toByteOffset: 2, as: UInt32.self)
    }
    var value = Data(count: 4)
    value.withUnsafeMutableBytes { buf in
        buf.storeBytes(of: UInt32(0x00000002).littleEndian, as: UInt32.self)  // RAM/host
    }
    cam.requestSendPTPCommand(command, outData: value,
                              sendCommandDelegate: self,
                              didSendCommandSelector: #selector(ptpCommandDone(_:didSendCommand:inData:response:error:contextInfo:)),
                              contextInfo: nil)
}

