#import "EDSDKShim.h"
#import "EDSDK.h"
#import "EDSDKTypes.h"
#import "EDSDKErrors.h"
#import <Foundation/Foundation.h>

// ---------------------------------------------------------------------------
// Global state — single-camera, single-session model matching the bridge CLI.
// ---------------------------------------------------------------------------

static EdsBaseRef   gCameraList     = NULL;
static EdsBaseRef   gCameraRef      = NULL;
static int          gCameraIndex    = -1;
static volatile BOOL gDownloadDone  = NO;
static NSString    *gDownloadedPath = nil;
static EdsShimError gDownloadError  = EDS_ERR_OK;

// ---------------------------------------------------------------------------
// Object event callback — fires on the RunLoop/EdsGetEvent thread
// ---------------------------------------------------------------------------

static EdsUInt32 EDSCALLBACK objectEventHandler(EdsUInt32 event,
                                                 EdsBaseRef object,
                                                 EdsVoid *context) {
    if (event != kEdsObjectEvent_DirItemRequestTransfer) return EDS_ERR_OK;

    NSString *destPath = (__bridge NSString *)context;

    EdsDirectoryItemInfo itemInfo = {0};
    EdsShimError err = EdsGetDirectoryItemInfo(object, &itemInfo);
    if (err != EDS_ERR_OK) {
        gDownloadError = err;
        gDownloadDone  = YES;
        return EDS_ERR_OK;
    }

    // Build a unique destination path preserving the camera's file extension.
    NSString *ext  = [NSString stringWithUTF8String:itemInfo.szFileName].pathExtension;
    if (ext.length == 0) ext = @"jpg";
    NSString *path = [[destPath stringByDeletingPathExtension]
                      stringByAppendingPathExtension:ext];

    EdsStreamRef stream = NULL;
    err = EdsCreateFileStream(path.fileSystemRepresentation,
                              kEdsFileCreateDisposition_CreateAlways,
                              kEdsAccess_ReadWrite,
                              &stream);
    if (err != EDS_ERR_OK) {
        gDownloadError = err;
        gDownloadDone  = YES;
        return EDS_ERR_OK;
    }

    err = EdsDownload(object, itemInfo.size, stream);
    EdsDownloadComplete(object);
    EdsRelease(stream);

    if (err == EDS_ERR_OK) {
        gDownloadedPath = path;
        gDownloadError  = EDS_ERR_OK;
    } else {
        gDownloadError = err;
    }
    gDownloadDone = YES;
    return EDS_ERR_OK;
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

EdsShimError edss_initialize(void) {
    return EdsInitializeSDK();
}

EdsShimError edss_terminate(void) {
    if (gCameraRef)  { EdsRelease(gCameraRef);  gCameraRef  = NULL; }
    if (gCameraList) { EdsRelease(gCameraList); gCameraList = NULL; }
    return EdsTerminateSDK();
}

EdsShimError edss_discover(EdsShimDeviceInfo *infos, int maxCount, int *outCount) {
    if (gCameraList) { EdsRelease(gCameraList); gCameraList = NULL; }

    EdsShimError err = EdsGetCameraList(&gCameraList);
    if (err != EDS_ERR_OK) { *outCount = 0; return err; }

    EdsUInt32 count = 0;
    EdsGetChildCount(gCameraList, &count);
    *outCount = (int)MIN(count, (EdsUInt32)maxCount);

    for (int i = 0; i < *outCount; i++) {
        EdsBaseRef camRef = NULL;
        if (EdsGetChildAtIndex(gCameraList, i, &camRef) != EDS_ERR_OK) continue;

        EdsDeviceInfo info = {0};
        EdsGetDeviceInfo(camRef, &info);

        strncpy(infos[i].modelName,   info.szDeviceDescription, 255);
        strncpy(infos[i].portName,    info.szPortName,          255);
        strncpy(infos[i].serialNumber, info.szPortName,         255);

        // Try to read the actual serial number via property.
        EdsChar sn[64] = {0};
        EdsUInt32 snSize = sizeof(sn);
        if (EdsGetPropertyData(camRef, kEdsPropID_BodyIDEx, 0, snSize, sn) == EDS_ERR_OK && sn[0]) {
            strncpy(infos[i].serialNumber, sn, 255);
        }

        EdsRelease(camRef);
    }
    return EDS_ERR_OK;
}

EdsShimError edss_open_session(int cameraIndex) {
    if (gCameraRef) { EdsRelease(gCameraRef); gCameraRef = NULL; }
    if (!gCameraList) {
        EdsShimError e = EdsGetCameraList(&gCameraList);
        if (e != EDS_ERR_OK) return e;
    }

    EdsShimError err = EdsGetChildAtIndex(gCameraList, cameraIndex, &gCameraRef);
    if (err != EDS_ERR_OK) return err;
    gCameraIndex = cameraIndex;

    return EdsOpenSession(gCameraRef);
}

EdsShimError edss_close_session(void) {
    EdsShimError err = EDS_ERR_OK;
    if (gCameraRef) {
        EdsSetObjectEventHandler(gCameraRef, kEdsObjectEvent_All, NULL, NULL);
        err = EdsCloseSession(gCameraRef);
        EdsRelease(gCameraRef);
        gCameraRef = NULL;
    }
    return err;
}

EdsShimError edss_set_save_to_host(void) {
    if (!gCameraRef) return EDS_ERR_INVALID_HANDLE;

    EdsUInt32 saveTo = kEdsSaveTo_Host;
    EdsShimError err = EdsSetPropertyData(gCameraRef, kEdsPropID_SaveTo, 0,
                                          sizeof(saveTo), &saveTo);
    if (err != EDS_ERR_OK) return err;

    // Tell the camera the host has effectively unlimited capacity.
    EdsCapacity cap = { 0x7FFFFFFF, 0x1000, 1 };
    return EdsSetCapacity(gCameraRef, cap);
}

EdsShimError edss_capture(const char *destPath, int timeoutSeconds) {
    if (!gCameraRef) return EDS_ERR_INVALID_HANDLE;

    gDownloadDone   = NO;
    gDownloadedPath = nil;
    gDownloadError  = EDS_ERR_OK;

    NSString *path = [NSString stringWithUTF8String:destPath];

    // Register the object event handler — pass destPath as context.
    EdsShimError err = EdsSetObjectEventHandler(gCameraRef,
                                                kEdsObjectEvent_All,
                                                objectEventHandler,
                                                (__bridge EdsVoid *)path);
    if (err != EDS_ERR_OK) return err;

    err = EdsSendCommand(gCameraRef, kEdsCameraCommand_TakePicture, 0);
    if (err != EDS_ERR_OK) return err;

    // Poll EdsGetEvent until download completes or timeout.
    int pollMs   = 100;
    int maxPolls = (timeoutSeconds * 1000) / pollMs;
    for (int i = 0; i < maxPolls && !gDownloadDone; i++) {
        EdsGetEvent();
        [NSThread sleepForTimeInterval:pollMs / 1000.0];
    }

    EdsSetObjectEventHandler(gCameraRef, kEdsObjectEvent_All, NULL, NULL);

    if (!gDownloadDone)          return EDS_ERR_COMM_DISCONNECTED;
    if (gDownloadError != EDS_ERR_OK) return gDownloadError;

    // Write the actual saved path back into destPath buffer for the caller.
    // We do this by writing to a sidecar file: destPath + ".result"
    NSString *resultPath = [path stringByAppendingString:@".result"];
    [gDownloadedPath writeToFile:resultPath
                      atomically:YES
                        encoding:NSUTF8StringEncoding
                           error:nil];
    return EDS_ERR_OK;
}

int edss_battery_level(void) {
    if (!gCameraRef) return -1;
    EdsUInt32 level = 0;
    if (EdsGetPropertyData(gCameraRef, kEdsPropID_BatteryLevel, 0,
                           sizeof(level), &level) != EDS_ERR_OK) return -1;
    return (int)level;
}

