import Foundation
import CaptureDeskCore
import CaptureDeskVendorSupport
import EDSDKShim

// MARK: - IO helpers

func writeResponse<T: Encodable>(_ value: T) {
    guard let data = try? JSONEncoder().encode(value) else { return }
    var out = data
    out.append(0x0A)
    FileHandle.standardOutput.write(out)
}

func log(_ msg: String) {
    FileHandle.standardError.write(Data("[\(msg)]\n".utf8))
}

func fail(_ msg: String) -> Never {
    FileHandle.standardError.write(Data("[CanonBridge] fatal: \(msg)\n".utf8))
    exit(1)
}

// MARK: - EDSDK lifecycle

guard edss_initialize() == 0 else { fail("EdsInitializeSDK failed") }
log("CanonBridge started — EDSDK v13 initialized (arm64)")
defer { edss_terminate() }

// MARK: - Command dispatch (persistent loop — one JSON line per command)

let stdinHandle = FileHandle.standardInput
var buffer = Data()

while true {
    // Read one byte at a time until newline so the process stays alive.
    let byte = stdinHandle.readData(ofLength: 1)
    if byte.isEmpty { break }
    if byte.first == UInt8(ascii: "\n") {
        guard !buffer.isEmpty else { continue }
        let line = buffer
        buffer = Data()
        handleLine(line)
    } else {
        buffer.append(contentsOf: byte)
    }
}

func handleLine(_ data: Data) {
    let decoder = JSONDecoder()

    struct GenericRequest: Decodable { var command: BridgeCommand; var vendor: CameraVendor }
    guard let req = try? decoder.decode(GenericRequest.self, from: data) else {
        log("failed to decode request")
        return
    }

    log("cmd=\(req.command.rawValue)")

    switch req.command {

    // -------------------------------------------------------------------------
    case .profile:
        writeResponse(BridgeProfileResponse(profile: VendorBridgeProfile(
            connectionTransport: "edsdk-v13",
            supportsRemoteCapture: true,
            supportsLiveView: false,
            supportsExposureControl: false,
            supportsFileEvents: true,
            supportsReconnect: true,
            commandVersion: 1,
            operationalNotes: "Canon EDSDK v13.20.10 — arm64 native, save-to-host supported"
        )))

    // -------------------------------------------------------------------------
    case .discover:
        let maxCams = 16
        var infos = [EdsShimDeviceInfo](repeating: EdsShimDeviceInfo(), count: maxCams)
        var count: Int32 = 0
        let err = edss_discover(&infos, Int32(maxCams), &count)
        log("Found \(count) camera(s) (err=\(err))")

        let devices: [VendorDiscoveredCamera] = (0..<Int(count)).map { i in
            let model  = withUnsafeBytes(of: infos[i].modelName)  { String(cString: $0.baseAddress!.assumingMemoryBound(to: CChar.self)) }
            let serial = withUnsafeBytes(of: infos[i].serialNumber) { String(cString: $0.baseAddress!.assumingMemoryBound(to: CChar.self)) }
            let battery = Int(edss_battery_level())
            return VendorDiscoveredCamera(modelName: model, manufacturer: "Canon",
                                         serialNumber: serial.isEmpty ? "cam-\(i)" : serial,
                                         batteryLevel: battery < 0 ? 0 : battery)
        }
        writeResponse(BridgeDiscoverResponse(devices: devices))

    // -------------------------------------------------------------------------
    case .connect:
        struct ConnectReq: Decodable { var command: BridgeCommand; var vendor: CameraVendor; var serialNumber: String }
        let connReq = (try? decoder.decode(ConnectReq.self, from: data))

        // Find camera index matching serial (or use 0 if only one camera).
        var targetIndex: Int32 = 0
        if let sn = connReq?.serialNumber {
            let maxCams = 16
            var infos = [EdsShimDeviceInfo](repeating: EdsShimDeviceInfo(), count: maxCams)
            var count: Int32 = 0
            edss_discover(&infos, Int32(maxCams), &count)
            for i in 0..<Int(count) {
                let serial = withUnsafeBytes(of: infos[i].serialNumber) {
                    String(cString: $0.baseAddress!.assumingMemoryBound(to: CChar.self))
                }
                if serial == sn { targetIndex = Int32(i); break }
            }
        }

        let openErr = edss_open_session(targetIndex)
        guard openErr == 0 else {
            writeResponse(BridgeAckResponse(ok: false, error: "EdsOpenSession failed: \(openErr)"))
            return
        }
        let saveErr = edss_set_save_to_host()
        if saveErr != 0 { log("set_save_to_host warning: \(saveErr)") }
        writeResponse(BridgeAckResponse(ok: true, message: "Session open, save-to-host active"))

    // -------------------------------------------------------------------------
    case .disconnect:
        edss_close_session()
        writeResponse(BridgeAckResponse(ok: true, message: "Session closed"))

    // -------------------------------------------------------------------------
    case .capture:
        struct CaptureReq: Decodable { var command: BridgeCommand; var vendor: CameraVendor; var folderURL: URL }
        guard let capReq = try? decoder.decode(CaptureReq.self, from: data) else {
            writeResponse(BridgeAckResponse(ok: false, error: "Failed to decode capture request"))
            return
        }

        let folder = capReq.folderURL
        try? FileManager.default.createDirectory(at: folder, withIntermediateDirectories: true)

        let ts = Int(Date.now.timeIntervalSince1970)
        let destBase = folder.appendingPathComponent("CAP_\(ts).tmp").path

        let captureErr = edss_capture(destBase, 30)
        guard captureErr == 0 else {
            writeResponse(BridgeAckResponse(ok: false, error: "EDSDK capture error: \(captureErr)"))
            return
        }

        // Read back actual filename from sidecar written by the shim.
        let resultFile = destBase + ".result"
        let actualPath = (try? String(contentsOfFile: resultFile, encoding: .utf8)) ?? destBase
        try? FileManager.default.removeItem(atPath: resultFile)

        let fileURL = URL(fileURLWithPath: actualPath)
        guard FileManager.default.fileExists(atPath: fileURL.path) else {
            writeResponse(BridgeAckResponse(ok: false, error: "Captured file missing: \(fileURL.path)"))
            return
        }

        // Re-read the serial number / model name from the open session camera.
        var infos = [EdsShimDeviceInfo](repeating: EdsShimDeviceInfo(), count: 1)
        var count: Int32 = 0
        edss_discover(&infos, 1, &count)
        let cameraName = count > 0
            ? withUnsafeBytes(of: infos[0].modelName) { String(cString: $0.baseAddress!.assumingMemoryBound(to: CChar.self)) }
            : "Canon EOS Camera"

        let payload = VendorCapturePayload(
            fileURL: fileURL,
            cameraName: cameraName,
            lensName: "",
            iso: 0,
            shutterSpeed: "",
            aperture: 0
        )
        writeResponse(BridgeCaptureResponse(payload: payload))
    }
}

