import Foundation
import CaptureDeskCore
import CaptureDeskVendorSupport

// MARK: - Helpers

let gphoto2Path: String = {
    for p in ["/opt/homebrew/bin/gphoto2", "/usr/local/bin/gphoto2", "/usr/bin/gphoto2"] {
        if FileManager.default.isExecutableFile(atPath: p) { return p }
    }
    return "gphoto2"
}()

// Kill ptpcamerad so gphoto2 can claim the USB PTP session.
func releasePTPSession() {
    let p = Process()
    p.executableURL = URL(fileURLWithPath: "/usr/bin/pkill")
    p.arguments = ["-9", "ptpcamerad"]
    p.standardOutput = Pipe(); p.standardError = Pipe()
    try? p.run(); p.waitUntilExit()
    Thread.sleep(forTimeInterval: 0.8)
}

@discardableResult
func runGPhoto(_ args: [String], timeout: TimeInterval = 20) -> (stdout: String, stderr: String, status: Int32) {
    releasePTPSession()
    let proc = Process()
    proc.executableURL = URL(fileURLWithPath: gphoto2Path)
    proc.arguments = args
    let out = Pipe(), err = Pipe()
    proc.standardOutput = out; proc.standardError = err
    try? proc.run()
    let timer = DispatchWorkItem { proc.terminate() }
    DispatchQueue.global().asyncAfter(deadline: .now() + timeout, execute: timer)
    proc.waitUntilExit()
    timer.cancel()
    let o = String(data: out.fileHandleForReading.readDataToEndOfFile(), encoding: .utf8) ?? ""
    let e = String(data: err.fileHandleForReading.readDataToEndOfFile(), encoding: .utf8) ?? ""
    return (o, e, proc.terminationStatus)
}

func writeResponse<T: Encodable>(_ value: T) {
    guard var data = try? JSONEncoder().encode(value) else { return }
    data.append(0x0A)
    FileHandle.standardOutput.write(data)
}

func log(_ msg: String) {
    FileHandle.standardError.write(Data("[CanonBridge] \(msg)\n".utf8))
}

// MARK: - Device listing helper

func parseAutoDetect(_ output: String) -> [VendorDiscoveredCamera] {
    let lines = output.components(separatedBy: "\n")
    var portCol = 32
    if let header = lines.first, let r = header.range(of: "Port") {
        portCol = header.distance(from: header.startIndex, to: r.lowerBound)
    }
    return lines.dropFirst(2).compactMap { line -> VendorDiscoveredCamera? in
        let t = line.trimmingCharacters(in: .whitespaces)
        guard !t.isEmpty, !t.hasPrefix("-"), line.count > portCol else { return nil }
        let split = line.index(line.startIndex, offsetBy: portCol)
        let model = String(line[..<split]).trimmingCharacters(in: .whitespaces)
        let port  = String(line[split...]).trimmingCharacters(in: .whitespaces)
        guard !model.isEmpty else { return nil }

        var serial = port.replacingOccurrences(of: "usb:", with: "USB-").replacingOccurrences(of: ",", with: "-")
        if !port.isEmpty {
            let snOut = (try? runGPhoto(["--port", port, "--get-config", "/main/status/serialnumber"], timeout: 5))?.stdout ?? ""
            for snLine in snOut.components(separatedBy: "\n") {
                if snLine.contains("Current:") {
                    let v = snLine.replacingOccurrences(of: "Current:", with: "").trimmingCharacters(in: .whitespaces)
                    if !v.isEmpty && v != "0" { serial = v; break }
                }
            }
        }
        let mfr = model.lowercased().hasPrefix("canon") ? "Canon" :
                  model.lowercased().hasPrefix("nikon") ? "Nikon" : "Unknown"
        return VendorDiscoveredCamera(modelName: model, manufacturer: mfr,
                                     serialNumber: serial, batteryLevel: 0)
    }
}

// MARK: - Command loop (persistent — one JSON line per command)

log("CanonBridge started — gphoto2 backend (\(gphoto2Path))")

let stdinHandle = FileHandle.standardInput
var buf = Data()

while true {
    let byte = stdinHandle.readData(ofLength: 1)
    if byte.isEmpty { break }
    if byte.first == UInt8(ascii: "\n") {
        guard !buf.isEmpty else { continue }
        let line = buf; buf = Data()
        handleLine(line)
    } else {
        buf.append(contentsOf: byte)
    }
}

func handleLine(_ data: Data) {
    let decoder = JSONDecoder()
    struct GenericReq: Decodable { var command: BridgeCommand; var vendor: CameraVendor }
    guard let req = try? decoder.decode(GenericReq.self, from: data) else { return }
    log("cmd=\(req.command.rawValue)")

    switch req.command {

    case .profile:
        writeResponse(BridgeProfileResponse(profile: VendorBridgeProfile(
            connectionTransport: "gphoto2",
            supportsRemoteCapture: true,
            supportsLiveView: false,
            supportsExposureControl: false,
            supportsFileEvents: false,
            supportsReconnect: true,
            commandVersion: 1,
            operationalNotes: "gphoto2 PTP — save-to-host, no card required"
        )))

    case .discover:
        let result = runGPhoto(["--auto-detect"], timeout: 10)
        let devices = parseAutoDetect(result.stdout)
        log("Found \(devices.count) camera(s)")
        writeResponse(BridgeDiscoverResponse(devices: devices))

    case .connect:
        // Set capture target to Internal RAM (save to host, no card needed).
        runGPhoto(["--set-config", "capturetarget=0"], timeout: 8)
        let result = runGPhoto(["--auto-detect"], timeout: 8)
        let ok = result.status == 0 && result.stdout.lowercased().contains("canon")
        writeResponse(BridgeAckResponse(ok: ok,
            message: ok ? "Connected — save-to-host active" : "Camera not found"))

    case .disconnect:
        writeResponse(BridgeAckResponse(ok: true, message: "Disconnected"))

    case .capture:
        struct CaptureReq: Decodable { var command: BridgeCommand; var vendor: CameraVendor; var folderURL: URL }
        guard let capReq = try? decoder.decode(CaptureReq.self, from: data) else {
            writeResponse(BridgeAckResponse(ok: false, error: "Bad capture request"))
            return
        }

        let folder = capReq.folderURL
        try? FileManager.default.createDirectory(at: folder, withIntermediateDirectories: true)

        // Re-assert save-to-host before every capture.
        runGPhoto(["--set-config", "capturetarget=0"], timeout: 8)

        let ts = Int(Date.now.timeIntervalSince1970)
        let tmpl = folder.appendingPathComponent("CAP_\(ts).%C").path
        let (captureOut, captureErr, status) = runGPhoto(
            ["--capture-image-and-download", "--filename", tmpl, "--force-overwrite"],
            timeout: 30
        )

        var downloadedURL: URL?
        let combined = captureOut + "\n" + captureErr
        for line in combined.components(separatedBy: "\n") {
            let lower = line.lowercased()
            if lower.contains("saving file as") || lower.contains("new file") {
                if let last = line.trimmingCharacters(in: .whitespaces).components(separatedBy: " ").last,
                   last.hasPrefix("/"),
                   FileManager.default.fileExists(atPath: last) {
                    downloadedURL = URL(fileURLWithPath: last)
                    break
                }
            }
        }

        if downloadedURL == nil {
            let exts = Set(["cr3","cr2","nef","arw","jpg","jpeg","tif","tiff"])
            let cutoff = Date.now.addingTimeInterval(-60)
            downloadedURL = (try? FileManager.default.contentsOfDirectory(
                at: folder, includingPropertiesForKeys: [.contentModificationDateKey]
            ))?.filter { exts.contains($0.pathExtension.lowercased()) }
              .compactMap { url -> (URL, Date)? in
                  let d = (try? url.resourceValues(forKeys: [.contentModificationDateKey]).contentModificationDate) ?? .distantPast
                  return d >= cutoff ? (url, d) : nil
              }.sorted { $0.1 > $1.1 }.first?.0
        }

        guard let fileURL = downloadedURL else {
            writeResponse(BridgeAckResponse(ok: false,
                error: "Capture failed (exit \(status)). \(combined.prefix(300))"))
            return
        }

        var cameraName = "Canon EOS Camera"
        let detectOut = runGPhoto(["--auto-detect"], timeout: 5).stdout
        cameraName = parseAutoDetect(detectOut).first?.modelName ?? cameraName

        writeResponse(BridgeCaptureResponse(payload: VendorCapturePayload(
            fileURL: fileURL, cameraName: cameraName,
            lensName: "", iso: 0, shutterSpeed: "", aperture: 0
        )))
    }
}

